// iter002_register_tile.cu - Register-tiled matmul for improved arithmetic intensity
// Bottleneck addressed: memory_bandwidth (iter001 achieved only 24% of baseline)
// Idea: Larger tiles (128x128) with register blocking (8x8 per thread)

#include <cuda_fp16.h>
#include <cuda_runtime.h>
#include <stdio.h>
#include <stdlib.h>

constexpr int M = 512;
constexpr int N = 16384;
constexpr int K = 16384;

// Larger tile dimensions for better arithmetic intensity
constexpr int BM = 128;
constexpr int BN = 128;
constexpr int BK = 16;

// Register tile: each thread computes TM x TN elements
constexpr int TM = 8;
constexpr int TN = 8;

// Thread block: (BM/TM) x (BN/TN) = 16 x 16 = 256 threads
constexpr int THREADS_X = BN / TN;  // 16
constexpr int THREADS_Y = BM / TM;  // 16

__global__ void matmul_register_tile(
    const half* __restrict__ A,
    const half* __restrict__ B,
    half* __restrict__ C,
    int m, int n, int k
) {
    // Shared memory with padding to avoid bank conflicts
    __shared__ half As[BM][BK + 1];
    __shared__ half Bs[BK][BN + 1];

    int tx = threadIdx.x;
    int ty = threadIdx.y;
    int bx = blockIdx.x;
    int by = blockIdx.y;

    // Starting row/col for this thread's register tile
    int row_start = by * BM + ty * TM;
    int col_start = bx * BN + tx * TN;

    // Register accumulators
    float acc[TM][TN];
    #pragma unroll
    for (int i = 0; i < TM; ++i) {
        #pragma unroll
        for (int j = 0; j < TN; ++j) {
            acc[i][j] = 0.0f;
        }
    }

    // Register fragments for A and B
    half a_frag[TM];
    half b_frag[TN];

    int num_tiles = (k + BK - 1) / BK;
    int tid = ty * THREADS_X + tx;
    int total_threads = THREADS_X * THREADS_Y;

    for (int tile = 0; tile < num_tiles; ++tile) {
        // Cooperative load of A tile into shared memory
        // Each thread loads multiple elements
        int a_loads = (BM * BK + total_threads - 1) / total_threads;
        for (int i = 0; i < a_loads; ++i) {
            int idx = tid + i * total_threads;
            if (idx < BM * BK) {
                int r = idx / BK;
                int c = idx % BK;
                int global_row = by * BM + r;
                int global_col = tile * BK + c;
                if (global_row < m && global_col < k) {
                    As[r][c] = A[global_row * k + global_col];
                } else {
                    As[r][c] = __float2half(0.0f);
                }
            }
        }

        // Cooperative load of B tile into shared memory
        int b_loads = (BK * BN + total_threads - 1) / total_threads;
        for (int i = 0; i < b_loads; ++i) {
            int idx = tid + i * total_threads;
            if (idx < BK * BN) {
                int r = idx / BN;
                int c = idx % BN;
                int global_row = tile * BK + r;
                int global_col = bx * BN + c;
                if (global_row < k && global_col < n) {
                    Bs[r][c] = B[global_row * n + global_col];
                } else {
                    Bs[r][c] = __float2half(0.0f);
                }
            }
        }

        __syncthreads();

        // Compute register tile
        #pragma unroll
        for (int kk = 0; kk < BK; ++kk) {
            // Load A fragment
            #pragma unroll
            for (int i = 0; i < TM; ++i) {
                a_frag[i] = As[ty * TM + i][kk];
            }
            // Load B fragment
            #pragma unroll
            for (int j = 0; j < TN; ++j) {
                b_frag[j] = Bs[kk][tx * TN + j];
            }
            // Accumulate
            #pragma unroll
            for (int i = 0; i < TM; ++i) {
                #pragma unroll
                for (int j = 0; j < TN; ++j) {
                    acc[i][j] += __half2float(a_frag[i]) * __half2float(b_frag[j]);
                }
            }
        }

        __syncthreads();
    }

    // Write results
    #pragma unroll
    for (int i = 0; i < TM; ++i) {
        int row = row_start + i;
        if (row < m) {
            #pragma unroll
            for (int j = 0; j < TN; ++j) {
                int col = col_start + j;
                if (col < n) {
                    C[row * n + col] = __float2half(acc[i][j]);
                }
            }
        }
    }
}

float benchmark_kernel(
    const half* d_A, const half* d_B, half* d_C,
    int m, int n, int k,
    int warmup, int iters
) {
    dim3 block(THREADS_X, THREADS_Y);
    dim3 grid((n + BN - 1) / BN, (m + BM - 1) / BM);

    for (int i = 0; i < warmup; ++i) {
        matmul_register_tile<<<grid, block>>>(d_A, d_B, d_C, m, n, k);
    }
    cudaDeviceSynchronize();

    cudaEvent_t start, stop;
    cudaEventCreate(&start);
    cudaEventCreate(&stop);

    cudaEventRecord(start);
    for (int i = 0; i < iters; ++i) {
        matmul_register_tile<<<grid, block>>>(d_A, d_B, d_C, m, n, k);
    }
    cudaEventRecord(stop);
    cudaEventSynchronize(stop);

    float ms = 0.0f;
    cudaEventElapsedTime(&ms, start, stop);
    cudaEventDestroy(start);
    cudaEventDestroy(stop);

    return ms / iters;
}

void init_matrix_random(half* mat, int rows, int cols, unsigned int seed) {
    srand(seed);
    for (int i = 0; i < rows * cols; ++i) {
        float val = (float)(rand() % 1000) / 1000.0f - 0.5f;
        mat[i] = __float2half(val);
    }
}

int main(int argc, char** argv) {
    int warmup = 5;
    int iters = 10;

    if (argc > 1) warmup = atoi(argv[1]);
    if (argc > 2) iters = atoi(argv[2]);

    size_t size_A = (size_t)M * K * sizeof(half);
    size_t size_B = (size_t)K * N * sizeof(half);
    size_t size_C = (size_t)M * N * sizeof(half);

    half *h_A = (half*)malloc(size_A);
    half *h_B = (half*)malloc(size_B);
    half *h_C = (half*)malloc(size_C);

    init_matrix_random(h_A, M, K, 42);
    init_matrix_random(h_B, K, N, 43);

    half *d_A, *d_B, *d_C;
    cudaMalloc(&d_A, size_A);
    cudaMalloc(&d_B, size_B);
    cudaMalloc(&d_C, size_C);

    cudaMemcpy(d_A, h_A, size_A, cudaMemcpyHostToDevice);
    cudaMemcpy(d_B, h_B, size_B, cudaMemcpyHostToDevice);

    float time_ms = benchmark_kernel(d_A, d_B, d_C, M, N, K, warmup, iters);

    double flops = 2.0 * M * N * K;
    double tflops = flops / (time_ms * 1e-3) / 1e12;

    printf("Shape: %dx%dx%d\n", M, N, K);
    printf("Time: %.3f ms\n", time_ms);
    printf("TFLOPS: %.2f\n", tflops);

    cudaMemcpy(h_C, d_C, size_C, cudaMemcpyDeviceToHost);

    cudaFree(d_A);
    cudaFree(d_B);
    cudaFree(d_C);
    free(h_A);
    free(h_B);
    free(h_C);

    return 0;
}

// iter003_vectorized.cu - Vectorized matmul with half2 loads
// Idea: Use half2 for coalesced 4-byte loads, moderate tiles (64x64)

#include <cuda_fp16.h>
#include <cuda_runtime.h>
#include <stdio.h>
#include <stdlib.h>

constexpr int M = 512;
constexpr int N = 16384;
constexpr int K = 16384;

// Moderate tile size with vectorization
constexpr int TILE_M = 64;
constexpr int TILE_N = 64;
constexpr int TILE_K = 16;

// Thread configuration: 32 warps per block for better occupancy
constexpr int BLOCK_DIM_X = 32;
constexpr int BLOCK_DIM_Y = 8;

__global__ void matmul_vectorized(
    const half* __restrict__ A,
    const half* __restrict__ B,
    half* __restrict__ C,
    int m, int n, int k
) {
    // Shared memory
    __shared__ half As[TILE_M][TILE_K + 1];
    __shared__ half Bs[TILE_K][TILE_N + 1];

    int tx = threadIdx.x;
    int ty = threadIdx.y;
    int bx = blockIdx.x;
    int by = blockIdx.y;

    // Each thread computes a 2x2 tile of output
    int row0 = by * TILE_M + ty * (TILE_M / BLOCK_DIM_Y);
    int col0 = bx * TILE_N + tx * 2;

    float acc[8][2] = {0};  // 8 rows, 2 cols per thread

    int tid = ty * BLOCK_DIM_X + tx;
    int total_threads = BLOCK_DIM_X * BLOCK_DIM_Y;

    for (int tile = 0; tile < (k + TILE_K - 1) / TILE_K; ++tile) {
        // Load A tile - each thread loads one element
        for (int offset = 0; offset < TILE_M * TILE_K; offset += total_threads) {
            int idx = tid + offset;
            if (idx < TILE_M * TILE_K) {
                int r = idx / TILE_K;
                int c = idx % TILE_K;
                int gr = by * TILE_M + r;
                int gc = tile * TILE_K + c;
                As[r][c] = (gr < m && gc < k) ? A[gr * k + gc] : __float2half(0.0f);
            }
        }

        // Load B tile
        for (int offset = 0; offset < TILE_K * TILE_N; offset += total_threads) {
            int idx = tid + offset;
            if (idx < TILE_K * TILE_N) {
                int r = idx / TILE_N;
                int c = idx % TILE_N;
                int gr = tile * TILE_K + r;
                int gc = bx * TILE_N + c;
                Bs[r][c] = (gr < k && gc < n) ? B[gr * n + gc] : __float2half(0.0f);
            }
        }

        __syncthreads();

        // Compute
        #pragma unroll
        for (int kk = 0; kk < TILE_K; ++kk) {
            half2 b_vec = *reinterpret_cast<const half2*>(&Bs[kk][tx * 2]);
            float b0 = __half2float(b_vec.x);
            float b1 = __half2float(b_vec.y);

            #pragma unroll
            for (int i = 0; i < 8; ++i) {
                float a_val = __half2float(As[ty * 8 + i][kk]);
                acc[i][0] += a_val * b0;
                acc[i][1] += a_val * b1;
            }
        }

        __syncthreads();
    }

    // Write results
    #pragma unroll
    for (int i = 0; i < 8; ++i) {
        int row = row0 + i;
        if (row < m) {
            if (col0 < n) {
                C[row * n + col0] = __float2half(acc[i][0]);
            }
            if (col0 + 1 < n) {
                C[row * n + col0 + 1] = __float2half(acc[i][1]);
            }
        }
    }
}

float benchmark_kernel(
    const half* d_A, const half* d_B, half* d_C,
    int m, int n, int k,
    int warmup, int iters
) {
    dim3 block(BLOCK_DIM_X, BLOCK_DIM_Y);
    dim3 grid((n + TILE_N - 1) / TILE_N, (m + TILE_M - 1) / TILE_M);

    for (int i = 0; i < warmup; ++i) {
        matmul_vectorized<<<grid, block>>>(d_A, d_B, d_C, m, n, k);
    }
    cudaDeviceSynchronize();

    cudaEvent_t start, stop;
    cudaEventCreate(&start);
    cudaEventCreate(&stop);

    cudaEventRecord(start);
    for (int i = 0; i < iters; ++i) {
        matmul_vectorized<<<grid, block>>>(d_A, d_B, d_C, m, n, k);
    }
    cudaEventRecord(stop);
    cudaEventSynchronize(stop);

    float ms = 0.0f;
    cudaEventElapsedTime(&ms, start, stop);
    cudaEventDestroy(start);
    cudaEventDestroy(stop);

    return ms / iters;
}

void init_matrix_random(half* mat, int rows, int cols, unsigned int seed) {
    srand(seed);
    for (int i = 0; i < rows * cols; ++i) {
        float val = (float)(rand() % 1000) / 1000.0f - 0.5f;
        mat[i] = __float2half(val);
    }
}

int main(int argc, char** argv) {
    int warmup = 5;
    int iters = 10;

    if (argc > 1) warmup = atoi(argv[1]);
    if (argc > 2) iters = atoi(argv[2]);

    size_t size_A = (size_t)M * K * sizeof(half);
    size_t size_B = (size_t)K * N * sizeof(half);
    size_t size_C = (size_t)M * N * sizeof(half);

    half *h_A = (half*)malloc(size_A);
    half *h_B = (half*)malloc(size_B);
    half *h_C = (half*)malloc(size_C);

    init_matrix_random(h_A, M, K, 42);
    init_matrix_random(h_B, K, N, 43);

    half *d_A, *d_B, *d_C;
    cudaMalloc(&d_A, size_A);
    cudaMalloc(&d_B, size_B);
    cudaMalloc(&d_C, size_C);

    cudaMemcpy(d_A, h_A, size_A, cudaMemcpyHostToDevice);
    cudaMemcpy(d_B, h_B, size_B, cudaMemcpyHostToDevice);

    float time_ms = benchmark_kernel(d_A, d_B, d_C, M, N, K, warmup, iters);

    double flops = 2.0 * M * N * K;
    double tflops = flops / (time_ms * 1e-3) / 1e12;

    printf("Shape: %dx%dx%d\n", M, N, K);
    printf("Time: %.3f ms\n", time_ms);
    printf("TFLOPS: %.2f\n", tflops);

    cudaFree(d_A);
    cudaFree(d_B);
    cudaFree(d_C);
    free(h_A);
    free(h_B);
    free(h_C);

    return 0;
}

// iter004_coalesced.cu - Coalesced memory access with optimized tile sizes
// Focus on memory coalescing and avoiding bank conflicts

#include <cuda_fp16.h>
#include <cuda_runtime.h>
#include <stdio.h>
#include <stdlib.h>

constexpr int M = 512;
constexpr int N = 16384;
constexpr int K = 16384;

// Optimal tile size for Ampere: 64x64x16
constexpr int TILE_M = 64;
constexpr int TILE_N = 64;
constexpr int TILE_K = 16;

// Thread block: 16x16 = 256 threads (8 warps)
constexpr int BLOCK_DIM_X = 16;
constexpr int BLOCK_DIM_Y = 16;

// Each thread computes a 4x4 sub-tile
constexpr int THREAD_TILE_M = 4;
constexpr int THREAD_TILE_N = 4;

__global__ void matmul_coalesced(
    const half* __restrict__ A,
    const half* __restrict__ B,
    half* __restrict__ C,
    int m, int n, int k
) {
    // Shared memory with padding to avoid bank conflicts
    __shared__ half As[TILE_M][TILE_K + 2];
    __shared__ half Bs[TILE_K][TILE_N + 2];

    const int tx = threadIdx.x;
    const int ty = threadIdx.y;
    const int bx = blockIdx.x;
    const int by = blockIdx.y;

    // Global starting positions
    const int row_start = by * TILE_M + ty * THREAD_TILE_M;
    const int col_start = bx * TILE_N + tx * THREAD_TILE_N;

    // Register accumulators
    float acc[THREAD_TILE_M][THREAD_TILE_N] = {0.0f};

    // Precompute thread position for loading
    const int tid = ty * BLOCK_DIM_X + tx;

    for (int tile = 0; tile < (k + TILE_K - 1) / TILE_K; ++tile) {
        // Load A: each thread loads 4 elements (coalesced along K dimension)
        // Total: 256 threads * 4 elements = 1024 = 64 * 16 ✓
        #pragma unroll
        for (int i = 0; i < 4; ++i) {
            int row = (tid / TILE_K) * 4 + i;
            int col = tid % TILE_K;
            int g_row = by * TILE_M + row;
            int g_col = tile * TILE_K + col;
            As[row][col] = (g_row < m && g_col < k) ? A[g_row * k + g_col] : __float2half(0.0f);
        }

        // Load B: each thread loads 4 elements (coalesced along N dimension)
        #pragma unroll
        for (int i = 0; i < 4; ++i) {
            int row = tid / TILE_N;
            int col = (tid % TILE_N / 4) * 4 + i;
            if (tid < TILE_K * TILE_N / 4) {
                int actual_row = (tid * 4) / TILE_N;
                int actual_col = (tid * 4 + i) % TILE_N;
                int g_row = tile * TILE_K + actual_row;
                int g_col = bx * TILE_N + actual_col;
                Bs[actual_row][actual_col] = (g_row < k && g_col < n) ? B[g_row * n + g_col] : __float2half(0.0f);
            }
        }

        __syncthreads();

        // Compute: each thread computes 4x4 output
        #pragma unroll
        for (int kk = 0; kk < TILE_K; ++kk) {
            float a[THREAD_TILE_M];
            float b[THREAD_TILE_N];

            #pragma unroll
            for (int i = 0; i < THREAD_TILE_M; ++i) {
                a[i] = __half2float(As[ty * THREAD_TILE_M + i][kk]);
            }

            #pragma unroll
            for (int j = 0; j < THREAD_TILE_N; ++j) {
                b[j] = __half2float(Bs[kk][tx * THREAD_TILE_N + j]);
            }

            #pragma unroll
            for (int i = 0; i < THREAD_TILE_M; ++i) {
                #pragma unroll
                for (int j = 0; j < THREAD_TILE_N; ++j) {
                    acc[i][j] += a[i] * b[j];
                }
            }
        }

        __syncthreads();
    }

    // Write output
    #pragma unroll
    for (int i = 0; i < THREAD_TILE_M; ++i) {
        int row = row_start + i;
        if (row < m) {
            #pragma unroll
            for (int j = 0; j < THREAD_TILE_N; ++j) {
                int col = col_start + j;
                if (col < n) {
                    C[row * n + col] = __float2half(acc[i][j]);
                }
            }
        }
    }
}

float benchmark_kernel(
    const half* d_A, const half* d_B, half* d_C,
    int m, int n, int k,
    int warmup, int iters
) {
    dim3 block(BLOCK_DIM_X, BLOCK_DIM_Y);
    dim3 grid((n + TILE_N - 1) / TILE_N, (m + TILE_M - 1) / TILE_M);

    for (int i = 0; i < warmup; ++i) {
