// iter006_wmma_double_buffer.cu - WMMA with double buffering for latency hiding
// Idea: Overlap memory loads with compute using double-buffered shared memory

#include <cuda_fp16.h>
#include <cuda_runtime.h>
#include <mma.h>
#include <stdio.h>
#include <stdlib.h>

using namespace nvcuda;

constexpr int M = 512;
constexpr int N = 16384;
constexpr int K = 16384;

constexpr int WMMA_M = 16;
constexpr int WMMA_N = 16;
constexpr int WMMA_K = 16;

// Smaller tiles for better occupancy
constexpr int TILE_M = 32;
constexpr int TILE_N = 64;
constexpr int TILE_K = 16;

// 2x2 warp arrangement = 4 warps = 128 threads
constexpr int WARPS_X = 4;
constexpr int WARPS_Y = 2;
constexpr int WARP_SIZE = 32;
constexpr int BLOCK_SIZE = WARPS_X * WARPS_Y * WARP_SIZE;

__global__ void matmul_wmma_double_buffer(
    const half* __restrict__ A,
    const half* __restrict__ B,
    half* __restrict__ C,
    int m, int n, int k
) {
    // Double-buffered shared memory
    __shared__ half As[2][TILE_M][TILE_K + 4];
    __shared__ half Bs[2][TILE_K][TILE_N + 4];

    int warpId = threadIdx.x / WARP_SIZE;
    int warpX = warpId % WARPS_X;
    int warpY = warpId / WARPS_X;

    int bx = blockIdx.x;
    int by = blockIdx.y;

    int warp_row = by * TILE_M + warpY * WMMA_M;
    int warp_col = bx * TILE_N + warpX * WMMA_N;

    // WMMA fragments
    wmma::fragment<wmma::matrix_a, WMMA_M, WMMA_N, WMMA_K, half, wmma::row_major> a_frag;
    wmma::fragment<wmma::matrix_b, WMMA_M, WMMA_N, WMMA_K, half, wmma::row_major> b_frag;
    wmma::fragment<wmma::accumulator, WMMA_M, WMMA_N, WMMA_K, float> c_frag;

    wmma::fill_fragment(c_frag, 0.0f);

    int tid = threadIdx.x;
    int num_tiles = (k + TILE_K - 1) / TILE_K;
    int buf = 0;

    // Preload first tile
    {
        int tile = 0;
        // Load A: TILE_M * TILE_K = 32 * 16 = 512 elements, 256 threads -> 2 per thread
        for (int i = 0; i < 2; ++i) {
            int idx = tid * 2 + i;
            if (idx < TILE_M * TILE_K) {
                int r = idx / TILE_K;
                int c = idx % TILE_K;
                int gr = by * TILE_M + r;
                int gc = tile * TILE_K + c;
                As[0][r][c] = (gr < m && gc < k) ? A[gr * k + gc] : __float2half(0.0f);
            }
        }
        // Load B: TILE_K * TILE_N = 16 * 64 = 1024 elements, 256 threads -> 4 per thread
        for (int i = 0; i < 4; ++i) {
            int idx = tid * 4 + i;
            if (idx < TILE_K * TILE_N) {
                int r = idx / TILE_N;
                int c = idx % TILE_N;
                int gr = tile * TILE_K + r;
                int gc = bx * TILE_N + c;
                Bs[0][r][c] = (gr < k && gc < n) ? B[gr * n + gc] : __float2half(0.0f);
            }
        }
    }

    __syncthreads();

    for (int tile = 0; tile < num_tiles; ++tile) {
        // Load next tile into alternate buffer (if not last tile)
        if (tile + 1 < num_tiles) {
            int next_buf = 1 - buf;
            int next_tile = tile + 1;

            for (int i = 0; i < 2; ++i) {
                int idx = tid * 2 + i;
                if (idx < TILE_M * TILE_K) {
                    int r = idx / TILE_K;
                    int c = idx % TILE_K;
                    int gr = by * TILE_M + r;
                    int gc = next_tile * TILE_K + c;
                    As[next_buf][r][c] = (gr < m && gc < k) ? A[gr * k + gc] : __float2half(0.0f);
                }
            }

            for (int i = 0; i < 4; ++i) {
                int idx = tid * 4 + i;
                if (idx < TILE_K * TILE_N) {
                    int r = idx / TILE_N;
                    int c = idx % TILE_N;
                    int gr = next_tile * TILE_K + r;
                    int gc = bx * TILE_N + c;
                    Bs[next_buf][r][c] = (gr < k && gc < n) ? B[gr * n + gc] : __float2half(0.0f);
                }
            }
        }

        // Compute using current buffer
        if (warp_row < m && warp_col < n) {
            wmma::load_matrix_sync(a_frag, &As[buf][warpY * WMMA_M][0], TILE_K + 4);
            wmma::load_matrix_sync(b_frag, &Bs[buf][0][warpX * WMMA_N], TILE_N + 4);
            wmma::mma_sync(c_frag, a_frag, b_frag, c_frag);
        }

        __syncthreads();
        buf = 1 - buf;
    }

    // Store results
    if (warp_row < m && warp_col < n) {
        wmma::fragment<wmma::accumulator, WMMA_M, WMMA_N, WMMA_K, half> c_frag_f16;
        for (int i = 0; i < c_frag.num_elements; ++i) {
            c_frag_f16.x[i] = __float2half(c_frag.x[i]);
        }
        wmma::store_matrix_sync(C + warp_row * n + warp_col, c_frag_f16, n, wmma::mem_row_major);
    }
}

float benchmark_kernel(
    const half* d_A, const half* d_B, half* d_C,
    int m, int n, int k,
    int warmup, int iters
) {
    dim3 block(BLOCK_SIZE);
    dim3 grid((n + TILE_N - 1) / TILE_N, (m + TILE_M - 1) / TILE_M);

    for (int i = 0; i < warmup; ++i) {
        matmul_wmma_double_buffer<<<grid, block>>>(d_A, d_B, d_C, m, n, k);
    }
    cudaDeviceSynchronize();

    cudaEvent_t start, stop;
    cudaEventCreate(&start);
    cudaEventCreate(&stop);

    cudaEventRecord(start);
    for (int i = 0; i < iters; ++i) {
        matmul_wmma_double_buffer<<<grid, block>>>(d_A, d_B, d_C, m, n, k);
    }
    cudaEventRecord(stop);
    cudaEventSynchronize(stop);

    float ms = 0.0f;
    cudaEventElapsedTime(&ms, start, stop);
    cudaEventDestroy(start);
    cudaEventDestroy(stop);

