// iter001_draft.cu - First tuning iteration for matmul bf16->fp32 512x16384x16384
// Input: A (M x K) bf16, B (K x N) bf16
// Output: C (M x N) fp32
// Uses WMMA for bf16 tensor core operations with fp32 accumulation

#include <cuda_bf16.h>
#include <cuda_fp16.h>
#include <mma.h>
#include <stdio.h>

using namespace nvcuda;

// WMMA dimensions for bf16
constexpr int WMMA_M = 16;
constexpr int WMMA_N = 16;
constexpr int WMMA_K = 16;

// Tile dimensions
constexpr int BLOCK_M = 64;
constexpr int BLOCK_N = 64;
constexpr int BLOCK_K = 16;

// Warp configuration: 4x2 warps per block
constexpr int WARPS_M = 4;
constexpr int WARPS_N = 2;
constexpr int WARP_SIZE = 32;

__global__ void matmul_bf16_fp32_wmma(
    const __nv_bfloat16* __restrict__ A,
    const __nv_bfloat16* __restrict__ B,
    float* __restrict__ C,
    int M, int N, int K
) {
    // Block position
    const int bx = blockIdx.x;
    const int by = blockIdx.y;

    // Warp position within block
    const int warpId = threadIdx.x / WARP_SIZE;
    const int warpM = warpId / WARPS_N;
    const int warpN = warpId % WARPS_N;

    // Lane within warp
    const int laneId = threadIdx.x % WARP_SIZE;

    // Global tile position
    const int tileM = by * BLOCK_M;
    const int tileN = bx * BLOCK_N;

    // WMMA fragment position within tile
    const int wmmaM = tileM + warpM * WMMA_M;
    const int wmmaN = tileN + warpN * WMMA_N;

    // Shared memory for tiles
    __shared__ __nv_bfloat16 sA[BLOCK_M][BLOCK_K];
    __shared__ __nv_bfloat16 sB[BLOCK_K][BLOCK_N];

    // WMMA fragments
    wmma::fragment<wmma::matrix_a, WMMA_M, WMMA_N, WMMA_K, __nv_bfloat16, wmma::row_major> a_frag;
    wmma::fragment<wmma::matrix_b, WMMA_M, WMMA_N, WMMA_K, __nv_bfloat16, wmma::row_major> b_frag;
    wmma::fragment<wmma::accumulator, WMMA_M, WMMA_N, WMMA_K, float> c_frag;

    // Initialize accumulator to zero
    wmma::fill_fragment(c_frag, 0.0f);

    // Loop over K dimension
    for (int k = 0; k < K; k += BLOCK_K) {
        // Load A tile to shared memory
        // Each thread loads multiple elements
        for (int i = threadIdx.x; i < BLOCK_M * BLOCK_K; i += blockDim.x) {
            int row = i / BLOCK_K;
            int col = i % BLOCK_K;
            int globalRow = tileM + row;
            int globalCol = k + col;
            if (globalRow < M && globalCol < K) {
                sA[row][col] = A[globalRow * K + globalCol];
            } else {
                sA[row][col] = __float2bfloat16(0.0f);
            }
        }

        // Load B tile to shared memory
        for (int i = threadIdx.x; i < BLOCK_K * BLOCK_N; i += blockDim.x) {
            int row = i / BLOCK_N;
            int col = i % BLOCK_N;
            int globalRow = k + row;
            int globalCol = tileN + col;
            if (globalRow < K && globalCol < N) {
                sB[row][col] = B[globalRow * N + globalCol];
            } else {
                sB[row][col] = __float2bfloat16(0.0f);
            }
        }

        __syncthreads();

        // Load fragments from shared memory and compute
        // Only first warp does the computation for each WMMA tile
        if (warpM < (BLOCK_M / WMMA_M) && warpN < (BLOCK_N / WMMA_N)) {
            wmma::load_matrix_sync(a_frag, &sA[warpM * WMMA_M][0], BLOCK_K);
            wmma::load_matrix_sync(b_frag, &sB[0][warpN * WMMA_N], BLOCK_N);
            wmma::mma_sync(c_frag, a_frag, b_frag, c_frag);
        }

        __syncthreads();
    }

    // Store result to global memory
    if (wmmaM < M && wmmaN < N) {
        wmma::store_matrix_sync(&C[wmmaM * N + wmmaN], c_frag, N, wmma::mem_row_major);
    }
}

int main(int argc, char** argv) {
    const int M = 512;
    const int N = 16384;
    const int K = 16384;

    int warmup = 5;
    int iters = 10;
    if (argc >= 2) warmup = atoi(argv[1]);
    if (argc >= 3) iters = atoi(argv[2]);

    size_t sizeA = M * K * sizeof(__nv_bfloat16);
    size_t sizeB = K * N * sizeof(__nv_bfloat16);
    size_t sizeC = M * N * sizeof(float);

    __nv_bfloat16 *d_A, *d_B;
    float *d_C;

    cudaMalloc(&d_A, sizeA);
    cudaMalloc(&d_B, sizeB);
    cudaMalloc(&d_C, sizeC);

    // Initialize with random values (simplified)
    __nv_bfloat16* h_A = new __nv_bfloat16[M * K];
    __nv_bfloat16* h_B = new __nv_bfloat16[K * N];
    for (int i = 0; i < M * K; i++) h_A[i] = __float2bfloat16((float)(rand() % 100) / 100.0f);
    for (int i = 0; i < K * N; i++) h_B[i] = __float2bfloat16((float)(rand() % 100) / 100.0f);

    cudaMemcpy(d_A, h_A, sizeA, cudaMemcpyHostToDevice);
    cudaMemcpy(d_B, h_B, sizeB, cudaMemcpyHostToDevice);

    dim3 block(WARPS_M * WARPS_N * WARP_SIZE);
    dim3 grid((N + BLOCK_N - 1) / BLOCK_N, (M + BLOCK_M - 1) / BLOCK_M);

    // Warmup
    for (int i = 0; i < warmup; i++) {
        matmul_bf16_fp32_wmma<<<grid, block>>>(d_A, d_B, d_C, M, N, K);
    }
    cudaDeviceSynchronize();

    // Benchmark
    cudaEvent_t start, stop;
    cudaEventCreate(&start);
    cudaEventCreate(&stop);

    cudaEventRecord(start);
    for (int i = 0; i < iters; i++) {
        matmul_bf16_fp32_wmma<<<grid, block>>>(d_A, d_B, d_C, M, N, K);
    }
    cudaEventRecord(stop);
    cudaEventSynchronize(stop);

    float ms = 0;
    cudaEventElapsedTime(&ms, start, stop);
    float avg_ms = ms / iters;

    double flops = 2.0 * M * N * K;
    double tflops = flops / (avg_ms * 1e-3) / 1e12;

    printf("Time: %.3f ms, TFLOPS: %.2f\n", avg_ms, tflops);

    // Cleanup
    delete[] h_A;
    delete[] h_B;
    cudaFree(d_A);
    cudaFree(d_B);
    cudaFree(d_C);
    cudaEventDestroy(start);
    cudaEventDestroy(stop);

    return 0;
}

// baseline_cublas.cu - cuBLAS baseline for matmul bf16->fp32
// Used ONLY for baseline measurement, NOT for tuning iterations

#include <cublas_v2.h>
#include <cuda_bf16.h>
#include <cuda_fp16.h>
#include <stdio.h>
#include <stdlib.h>

#define CHECK_CUDA(call) do { \
    cudaError_t err = call; \
    if (err != cudaSuccess) { \
        fprintf(stderr, "CUDA error at %s:%d: %s\n", __FILE__, __LINE__, cudaGetErrorString(err)); \
        exit(1); \
    } \
} while(0)

#define CHECK_CUBLAS(call) do { \
    cublasStatus_t status = call; \
    if (status != CUBLAS_STATUS_SUCCESS) { \
        fprintf(stderr, "cuBLAS error at %s:%d: %d\n", __FILE__, __LINE__, status); \
        exit(1); \
    } \
} while(0)

int main(int argc, char** argv) {
    const int M = 512;
    const int N = 16384;
    const int K = 16384;

    int warmup = 10;
    int iters = 20;
    if (argc >= 2) warmup = atoi(argv[1]);
    if (argc >= 3) iters = atoi(argv[2]);

    cublasHandle_t handle;
    CHECK_CUBLAS(cublasCreate(&handle));
    CHECK_CUBLAS(cublasSetMathMode(handle, CUBLAS_TENSOR_OP_MATH));

    // Allocate device memory
    __nv_bfloat16 *d_A, *d_B;
    float *d_C;

    CHECK_CUDA(cudaMalloc(&d_A, M * K * sizeof(__nv_bfloat16)));
    CHECK_CUDA(cudaMalloc(&d_B, K * N * sizeof(__nv_bfloat16)));
    CHECK_CUDA(cudaMalloc(&d_C, M * N * sizeof(float)));

    // Initialize with random values
    __nv_bfloat16* h_A = new __nv_bfloat16[M * K];
    __nv_bfloat16* h_B = new __nv_bfloat16[K * N];
    for (int i = 0; i < M * K; i++) h_A[i] = __float2bfloat16((float)(rand() % 100) / 100.0f);
    for (int i = 0; i < K * N; i++) h_B[i] = __float2bfloat16((float)(rand() % 100) / 100.0f);

    CHECK_CUDA(cudaMemcpy(d_A, h_A, M * K * sizeof(__nv_bfloat16), cudaMemcpyHostToDevice));
    CHECK_CUDA(cudaMemcpy(d_B, h_B, K * N * sizeof(__nv_bfloat16), cudaMemcpyHostToDevice));

    float alpha = 1.0f;
    float beta = 0.0f;

    // Warmup
    for (int i = 0; i < warmup; i++) {
        // cublasGemmEx: C = alpha * A * B + beta * C
        // Note: cuBLAS uses column-major, so we compute B^T * A^T = (A * B)^T
        CHECK_CUBLAS(cublasGemmEx(
            handle,
            CUBLAS_OP_N, CUBLAS_OP_N,
            N, M, K,  // Note: reversed for row-major
            &alpha,
            d_B, CUDA_R_16BF, N,  // B is K x N in row-major = N x K in col-major
            d_A, CUDA_R_16BF, K,  // A is M x K in row-major = K x M in col-major
            &beta,
            d_C, CUDA_R_32F, N,   // C is M x N in row-major = N x M in col-major
            CUBLAS_COMPUTE_32F,
            CUBLAS_GEMM_DEFAULT_TENSOR_OP
        ));
    }
    CHECK_CUDA(cudaDeviceSynchronize());

    // Benchmark
    cudaEvent_t start, stop;
    CHECK_CUDA(cudaEventCreate(&start));
    CHECK_CUDA(cudaEventCreate(&stop));

    CHECK_CUDA(cudaEventRecord(start));
    for (int i = 0; i < iters; i++) {
        CHECK_CUBLAS(cublasGemmEx(
            handle,
            CUBLAS_OP_N, CUBLAS_OP_N,
            N, M, K,
            &alpha,
            d_B, CUDA_R_16BF, N,
            d_A, CUDA_R_16BF, K,
            &beta,
            d_C, CUDA_R_32F, N,
            CUBLAS_COMPUTE_32F,
            CUBLAS_GEMM_DEFAULT_TENSOR_OP
        ));
    }
    CHECK_CUDA(cudaEventRecord(stop));
    CHECK_CUDA(cudaEventSynchronize(stop));

    float ms = 0;
    CHECK_CUDA(cudaEventElapsedTime(&ms, start, stop));
    float avg_ms = ms / iters;

    double flops = 2.0 * M * N * K;
    double tflops = flops / (avg_ms * 1e-3) / 1e12;

    printf("cuBLAS bf16->fp32: %.3f ms, %.2f TFLOPS\n", avg_ms, tflops);

    // Cleanup
    delete[] h_A;
    delete[] h_B;
    CHECK_CUDA(cudaFree(d_A));
    CHECK_CUDA(cudaFree(d_B));
    CHECK_CUDA(cudaFree(d_C));
    CHECK_CUDA(cudaEventDestroy(start));
    CHECK_CUDA(cudaEventDestroy(stop));
    CHECK_CUBLAS(cublasDestroy(handle));

    return 0;
}

// iter002_no_bank_conflict.cu - Fix shared memory bank conflicts
// Problem from ncu: 5-way bank conflict on shared memory loads (79.56% wavefronts)
// Solution: Add padding to shared memory to avoid bank conflicts
// 
// BF16 is 2 bytes. Shared memory has 32 banks, each 4 bytes wide.
// Two bf16 values share the same bank. With padding, we shift access patterns.

#include <cuda_bf16.h>
#include <cuda_fp16.h>
#include <mma.h>
#include <stdio.h>

using namespace nvcuda;

constexpr int WMMA_M = 16;
constexpr int WMMA_N = 16;
constexpr int WMMA_K = 16;

constexpr int BLOCK_M = 64;
constexpr int BLOCK_N = 64;
constexpr int BLOCK_K = 16;

// Padding to avoid bank conflicts
// Each row gets 8 extra bf16 values (16 bytes = 4 banks)
constexpr int SMEM_PAD = 8;

constexpr int WARPS_M = 2;
constexpr int WARPS_N = 2;
constexpr int WARP_SIZE = 32;
constexpr int NUM_WARPS = WARPS_M * WARPS_N;

__global__ void matmul_bf16_fp32_no_bank_conflict(
    const __nv_bfloat16* __restrict__ A,
    const __nv_bfloat16* __restrict__ B,
    float* __restrict__ C,
    int M, int N, int K
) {
    const int bx = blockIdx.x;
    const int by = blockIdx.y;

    const int warpId = threadIdx.x / WARP_SIZE;
    const int warpM = warpId / WARPS_N;
    const int warpN = warpId % WARPS_N;

    const int tileM = by * BLOCK_M;
    const int tileN = bx * BLOCK_N;

    // Padded shared memory to avoid bank conflicts
    __shared__ __nv_bfloat16 sA[BLOCK_M][BLOCK_K + SMEM_PAD];
    __shared__ __nv_bfloat16 sB[BLOCK_K][BLOCK_N + SMEM_PAD];

    // WMMA fragments - each warp handles 32x32 output (2x2 WMMA tiles)
    wmma::fragment<wmma::matrix_a, WMMA_M, WMMA_N, WMMA_K, __nv_bfloat16, wmma::row_major> a_frag[2];
    wmma::fragment<wmma::matrix_b, WMMA_M, WMMA_N, WMMA_K, __nv_bfloat16, wmma::row_major> b_frag[2];
    wmma::fragment<wmma::accumulator, WMMA_M, WMMA_N, WMMA_K, float> c_frag[2][2];

    // Initialize accumulators
    #pragma unroll
    for (int i = 0; i < 2; i++) {
        #pragma unroll
        for (int j = 0; j < 2; j++) {
            wmma::fill_fragment(c_frag[i][j], 0.0f);
        }
    }

    const int tid = threadIdx.x;

    // K-loop
    for (int k = 0; k < K; k += BLOCK_K) {
        // Load A tile with coalesced access
        // 128 threads, 64*16 = 1024 elements
        // Each thread loads 8 elements
        #pragma unroll
        for (int i = 0; i < (BLOCK_M * BLOCK_K) / (NUM_WARPS * WARP_SIZE); i++) {
            int idx = tid + i * NUM_WARPS * WARP_SIZE;
            int row = idx / BLOCK_K;
            int col = idx % BLOCK_K;
            int globalRow = tileM + row;
            int globalCol = k + col;
            if (globalRow < M && globalCol < K) {
                sA[row][col] = A[globalRow * K + globalCol];
            } else {
                sA[row][col] = __float2bfloat16(0.0f);
            }
        }

        // Load B tile with coalesced access
        #pragma unroll
        for (int i = 0; i < (BLOCK_K * BLOCK_N) / (NUM_WARPS * WARP_SIZE); i++) {
            int idx = tid + i * NUM_WARPS * WARP_SIZE;
            int row = idx / BLOCK_N;
            int col = idx % BLOCK_N;
            int globalRow = k + row;
            int globalCol = tileN + col;
            if (globalRow < K && globalCol < N) {
                sB[row][col] = B[globalRow * N + globalCol];
            } else {
                sB[row][col] = __float2bfloat16(0.0f);
            }
        }

        __syncthreads();

        // Compute WMMA - each warp handles 32x32 (2x2 WMMA tiles)
        int warpBaseM = warpM * 32;  // 0 or 32
        int warpBaseN = warpN * 32;  // 0 or 32

        #pragma unroll
        for (int i = 0; i < 2; i++) {
            wmma::load_matrix_sync(a_frag[i], &sA[warpBaseM + i * WMMA_M][0], BLOCK_K + SMEM_PAD);
        }

        #pragma unroll
        for (int j = 0; j < 2; j++) {
            wmma::load_matrix_sync(b_frag[j], &sB[0][warpBaseN + j * WMMA_N], BLOCK_N + SMEM_PAD);
        }

        #pragma unroll
        for (int i = 0; i < 2; i++) {
            #pragma unroll
            for (int j = 0; j < 2; j++) {
                wmma::mma_sync(c_frag[i][j], a_frag[i], b_frag[j], c_frag[i][j]);
            }
        }

        __syncthreads();
    }

    // Store results
    int warpBaseM = warpM * 32;
    int warpBaseN = warpN * 32;

    #pragma unroll
    for (int i = 0; i < 2; i++) {
        #pragma unroll
        for (int j = 0; j < 2; j++) {
            int outM = tileM + warpBaseM + i * WMMA_M;
            int outN = tileN + warpBaseN + j * WMMA_N;
            if (outM < M && outN < N) {
                wmma::store_matrix_sync(&C[outM * N + outN], c_frag[i][j], N, wmma::mem_row_major);
            }
        }
    }
}

int main(int argc, char** argv) {
    const int M = 512;
    const int N = 16384;
    const int K = 16384;

    int warmup = 5;
    int iters = 10;
    if (argc >= 2) warmup = atoi(argv[1]);
    if (argc >= 3) iters = atoi(argv[2]);

    __nv_bfloat16 *d_A, *d_B;
    float *d_C;

    cudaMalloc(&d_A, M * K * sizeof(__nv_bfloat16));
    cudaMalloc(&d_B, K * N * sizeof(__nv_bfloat16));
    cudaMalloc(&d_C, M * N * sizeof(float));

    __nv_bfloat16* h_A = new __nv_bfloat16[M * K];
    __nv_bfloat16* h_B = new __nv_bfloat16[K * N];
    for (int i = 0; i < M * K; i++) h_A[i] = __float2bfloat16((float)(rand() % 100) / 100.0f);
    for (int i = 0; i < K * N; i++) h_B[i] = __float2bfloat16((float)(rand() % 100) / 100.0f);

    cudaMemcpy(d_A, h_A, M * K * sizeof(__nv_bfloat16), cudaMemcpyHostToDevice);
    cudaMemcpy(d_B, h_B, K * N * sizeof(__nv_bfloat16), cudaMemcpyHostToDevice);

    dim3 block(NUM_WARPS * WARP_SIZE);
    dim3 grid((N + BLOCK_N - 1) / BLOCK_N, (M + BLOCK_M - 1) / BLOCK_M);

    for (int i = 0; i < warmup; i++) {
        matmul_bf16_fp32_no_bank_conflict<<<grid, block>>>(d_A, d_B, d_C, M, N, K);
    }
    cudaDeviceSynchronize();

    cudaEvent_t start, stop;
    cudaEventCreate(&start);
    cudaEventCreate(&stop);

    cudaEventRecord(start);
    for (int i = 0; i < iters; i++) {
        matmul_bf16_fp32_no_bank_conflict<<<grid, block>>>(d_A, d_B, d_C, M, N, K);
    }
    cudaEventRecord(stop);
    cudaEventSynchronize(stop);

    float ms = 0;
    cudaEventElapsedTime(&ms, start, stop);
    float avg_ms = ms / iters;

    double flops = 2.0 * M * N * K;
    double tflops = flops / (avg_ms * 1e-3) / 1e12;

    printf("Time: %.3f ms, TFLOPS: %.2f\n", avg_ms, tflops);

    delete[] h_A;
    delete[] h_B;
    cudaFree(d_A);
    cudaFree(d_B);
    cudaFree(d_C);
    cudaEventDestroy(start);
    cudaEventDestroy(stop);

    return 0;
}

// iter003_low_register.cu - Reduce register pressure for better occupancy
// Problem from ncu: 126 registers/thread -> only 33% occupancy (16/48 warps)
// Solution: Use __launch_bounds__ and simplify to 1 WMMA tile per warp

#include <cuda_bf16.h>
#include <cuda_fp16.h>
#include <mma.h>
#include <stdio.h>

using namespace nvcuda;

constexpr int WMMA_M = 16;
constexpr int WMMA_N = 16;
constexpr int WMMA_K = 16;

constexpr int BLOCK_M = 64;
constexpr int BLOCK_N = 64;
constexpr int BLOCK_K = 32;  // Larger K tile for better arithmetic intensity

constexpr int SMEM_PAD = 8;

// 4x4 warps = 16 warps per block, each handles 16x16 output
constexpr int WARPS_M = 4;
constexpr int WARPS_N = 4;
constexpr int WARP_SIZE = 32;
constexpr int NUM_WARPS = WARPS_M * WARPS_N;
constexpr int BLOCK_SIZE = NUM_WARPS * WARP_SIZE;  // 512 threads

// Limit registers to increase occupancy
// With 64 registers per thread: 65536/64 = 1024 threads/SM = 32 warps/SM
__launch_bounds__(BLOCK_SIZE, 2)  // 2 blocks per SM minimum
__global__ void matmul_bf16_fp32_low_register(
    const __nv_bfloat16* __restrict__ A,
    const __nv_bfloat16* __restrict__ B,
    float* __restrict__ C,
    int M, int N, int K
) {
    const int bx = blockIdx.x;
    const int by = blockIdx.y;

    const int warpId = threadIdx.x / WARP_SIZE;
    const int warpM = warpId / WARPS_N;
    const int warpN = warpId % WARPS_N;

    const int tileM = by * BLOCK_M;
    const int tileN = bx * BLOCK_N;

    // Padded shared memory
    __shared__ __nv_bfloat16 sA[BLOCK_M][BLOCK_K + SMEM_PAD];
    __shared__ __nv_bfloat16 sB[BLOCK_K][BLOCK_N + SMEM_PAD];

    // Single WMMA tile per warp (reduces register usage)
    wmma::fragment<wmma::matrix_a, WMMA_M, WMMA_N, WMMA_K, __nv_bfloat16, wmma::row_major> a_frag;
    wmma::fragment<wmma::matrix_b, WMMA_M, WMMA_N, WMMA_K, __nv_bfloat16, wmma::row_major> b_frag;
    wmma::fragment<wmma::accumulator, WMMA_M, WMMA_N, WMMA_K, float> c_frag;

    wmma::fill_fragment(c_frag, 0.0f);

    const int tid = threadIdx.x;
    const int laneId = tid % WARP_SIZE;

    // K-loop with larger K-tile
    for (int k = 0; k < K; k += BLOCK_K) {
        // Cooperative load of A tile (64x32 = 2048 elements, 512 threads = 4 per thread)
        #pragma unroll 4
        for (int i = 0; i < 4; i++) {
            int idx = tid * 4 + i;
            int row = idx / BLOCK_K;
            int col = idx % BLOCK_K;
            int globalRow = tileM + row;
            int globalCol = k + col;
            sA[row][col] = (globalRow < M && globalCol < K) ? 
                           A[globalRow * K + globalCol] : __float2bfloat16(0.0f);
        }

        // Cooperative load of B tile (32x64 = 2048 elements, 512 threads = 4 per thread)
        #pragma unroll 4
        for (int i = 0; i < 4; i++) {
            int idx = tid * 4 + i;
            int row = idx / BLOCK_N;
            int col = idx % BLOCK_N;
            int globalRow = k + row;
            int globalCol = tileN + col;
            sB[row][col] = (globalRow < K && globalCol < N) ? 
                           B[globalRow * N + globalCol] : __float2bfloat16(0.0f);
        }

        __syncthreads();

        // Compute WMMA - iterate over K in shared memory
        int warpBaseM = warpM * WMMA_M;
        int warpBaseN = warpN * WMMA_N;

        // Two WMMA_K iterations per BLOCK_K
        #pragma unroll 2
        for (int kk = 0; kk < BLOCK_K; kk += WMMA_K) {
            wmma::load_matrix_sync(a_frag, &sA[warpBaseM][kk], BLOCK_K + SMEM_PAD);
            wmma::load_matrix_sync(b_frag, &sB[kk][warpBaseN], BLOCK_N + SMEM_PAD);
            wmma::mma_sync(c_frag, a_frag, b_frag, c_frag);
        }

        __syncthreads();
    }

    // Store result
    int outM = tileM + warpM * WMMA_M;
    int outN = tileN + warpN * WMMA_N;

    if (outM < M && outN < N) {
        wmma::store_matrix_sync(&C[outM * N + outN], c_frag, N, wmma::mem_row_major);
    }
}

int main(int argc, char** argv) {
    const int M = 512;
    const int N = 16384;
    const int K = 16384;

    int warmup = 5;
    int iters = 10;
    if (argc >= 2) warmup = atoi(argv[1]);
    if (argc >= 3) iters = atoi(argv[2]);

    __nv_bfloat16 *d_A, *d_B;
    float *d_C;

    cudaMalloc(&d_A, M * K * sizeof(__nv_bfloat16));
    cudaMalloc(&d_B, K * N * sizeof(__nv_bfloat16));
    cudaMalloc(&d_C, M * N * sizeof(float));

    __nv_bfloat16* h_A = new __nv_bfloat16[M * K];
    __nv_bfloat16* h_B = new __nv_bfloat16[K * N];
    for (int i = 0; i < M * K; i++) h_A[i] = __float2bfloat16((float)(rand() % 100) / 100.0f);
    for (int i = 0; i < K * N; i++) h_B[i] = __float2bfloat16((float)(rand() % 100) / 100.0f);

    cudaMemcpy(d_A, h_A, M * K * sizeof(__nv_bfloat16), cudaMemcpyHostToDevice);
    cudaMemcpy(d_B, h_B, K * N * sizeof(__nv_bfloat16), cudaMemcpyHostToDevice);

    dim3 block(BLOCK_SIZE);
    dim3 grid((N + BLOCK_N - 1) / BLOCK_N, (M + BLOCK_M - 1) / BLOCK_M);

    for (int i = 0; i < warmup; i++) {
        matmul_bf16_fp32_low_register<<<grid, block>>>(d_A, d_B, d_C, M, N, K);
    }
    cudaDeviceSynchronize();

    cudaEvent_t start, stop;
    cudaEventCreate(&start);
    cudaEventCreate(&stop);

    cudaEventRecord(start);
    for (int i = 0; i < iters; i++) {
        matmul_bf16_fp32_low_register<<<grid, block>>>(d_A, d_B, d_C, M, N, K);
    }
    cudaEventRecord(stop);
    cudaEventSynchronize(stop);

    float ms = 0;
    cudaEventElapsedTime(&ms, start, stop);
    float avg_ms = ms / iters;

    double flops = 2.0 * M * N * K;
    double tflops = flops / (avg_ms * 1e-3) / 1e12;

    printf("Time: %.3f ms, TFLOPS: %.2f\n", avg_ms, tflops);

    delete[] h_A;
    delete[] h_B;
    cudaFree(d_A);
    cudaFree(d_B);
    cudaFree(d_C);
    cudaEventDestroy(start);
    cudaEventDestroy(stop);

    return 0;
}

// iter004_vectorized_ldg.cu - Use vectorized loads and __ldg for better memory access
// Problem from ncu: Uncoalesced L1->L2 loads (21.87% speedup potential)
// Solution: Use half2/bf162 vectorized loads and __ldg for read-only cache

#include <cuda_bf16.h>
#include <cuda_fp16.h>
#include <mma.h>
#include <stdio.h>

using namespace nvcuda;

constexpr int WMMA_M = 16;
constexpr int WMMA_N = 16;
constexpr int WMMA_K = 16;

constexpr int BLOCK_M = 64;
constexpr int BLOCK_N = 64;
constexpr int BLOCK_K = 16;

constexpr int SMEM_PAD = 8;

constexpr int WARPS_M = 2;
constexpr int WARPS_N = 2;
constexpr int WARP_SIZE = 32;
constexpr int NUM_WARPS = WARPS_M * WARPS_N;
constexpr int BLOCK_SIZE = NUM_WARPS * WARP_SIZE;

// bf162 vector type for vectorized loads
typedef __nv_bfloat162 bf162;

__device__ __forceinline__ bf162 load_bf162(const __nv_bfloat16* ptr) {
    return __ldg(reinterpret_cast<const bf162*>(ptr));
}

__global__ void matmul_bf16_fp32_vectorized(
    const __nv_bfloat16* __restrict__ A,
    const __nv_bfloat16* __restrict__ B,
    float* __restrict__ C,
    int M, int N, int K
) {
    const int bx = blockIdx.x;
    const int by = blockIdx.y;

    const int warpId = threadIdx.x / WARP_SIZE;
    const int warpM = warpId / WARPS_N;
    const int warpN = warpId % WARPS_N;

    const int tileM = by * BLOCK_M;
    const int tileN = bx * BLOCK_N;

    // Padded shared memory
    __shared__ __nv_bfloat16 sA[BLOCK_M][BLOCK_K + SMEM_PAD];
    __shared__ __nv_bfloat16 sB[BLOCK_K][BLOCK_N + SMEM_PAD];

    wmma::fragment<wmma::matrix_a, WMMA_M, WMMA_N, WMMA_K, __nv_bfloat16, wmma::row_major> a_frag[2];
    wmma::fragment<wmma::matrix_b, WMMA_M, WMMA_N, WMMA_K, __nv_bfloat16, wmma::row_major> b_frag[2];
    wmma::fragment<wmma::accumulator, WMMA_M, WMMA_N, WMMA_K, float> c_frag[2][2];

    #pragma unroll
    for (int i = 0; i < 2; i++) {
        #pragma unroll
        for (int j = 0; j < 2; j++) {
            wmma::fill_fragment(c_frag[i][j], 0.0f);
        }
    }

    const int tid = threadIdx.x;

    // Calculate how many bf162 pairs each thread loads
    // A: 64*16 = 1024 bf16 = 512 bf162, 128 threads = 4 bf162 per thread
    // B: 16*64 = 1024 bf16 = 512 bf162, 128 threads = 4 bf162 per thread

    for (int k = 0; k < K; k += BLOCK_K) {
        // Load A with vectorized access
        // Each thread loads 4 bf162 (8 bf16 values)
        #pragma unroll 4
        for (int i = 0; i < 4; i++) {
            int idx = tid * 4 + i;  // bf162 index
            int elem_idx = idx * 2;  // bf16 index
            int row = elem_idx / BLOCK_K;
            int col = elem_idx % BLOCK_K;

            if (row < BLOCK_M) {
                int globalRow = tileM + row;
                int globalCol = k + col;

                if (globalRow < M && globalCol + 1 < K) {
                    bf162 val = load_bf162(&A[globalRow * K + globalCol]);
                    sA[row][col] = val.x;
                    sA[row][col + 1] = val.y;
                } else if (globalRow < M && globalCol < K) {
                    sA[row][col] = A[globalRow * K + globalCol];
                    sA[row][col + 1] = __float2bfloat16(0.0f);
                } else {
                    sA[row][col] = __float2bfloat16(0.0f);
                    sA[row][col + 1] = __float2bfloat16(0.0f);
                }
            }
        }

        // Load B with vectorized access
        #pragma unroll 4
        for (int i = 0; i < 4; i++) {
            int idx = tid * 4 + i;
            int elem_idx = idx * 2;
            int row = elem_idx / BLOCK_N;
            int col = elem_idx % BLOCK_N;

            if (row < BLOCK_K) {
                int globalRow = k + row;
                int globalCol = tileN + col;

                if (globalRow < K && globalCol + 1 < N) {
                    bf162 val = load_bf162(&B[globalRow * N + globalCol]);
                    sB[row][col] = val.x;
                    sB[row][col + 1] = val.y;
                } else if (globalRow < K && globalCol < N) {
                    sB[row][col] = B[globalRow * N + globalCol];
                    sB[row][col + 1] = __float2bfloat16(0.0f);
                } else {
                    sB[row][col] = __float2bfloat16(0.0f);
                    sB[row][col + 1] = __float2bfloat16(0.0f);
                }
            }
        }

        __syncthreads();

        // Compute WMMA
        int warpBaseM = warpM * 32;
        int warpBaseN = warpN * 32;

        #pragma unroll
        for (int i = 0; i < 2; i++) {
            wmma::load_matrix_sync(a_frag[i], &sA[warpBaseM + i * WMMA_M][0], BLOCK_K + SMEM_PAD);
        }

        #pragma unroll
        for (int j = 0; j < 2; j++) {
            wmma::load_matrix_sync(b_frag[j], &sB[0][warpBaseN + j * WMMA_N], BLOCK_N + SMEM_PAD);
        }

        #pragma unroll
        for (int i = 0; i < 2; i++) {
            #pragma unroll
            for (int j = 0; j < 2; j++) {
                wmma::mma_sync(c_frag[i][j], a_frag[i], b_frag[j], c_frag[i][j]);
            }
        }

        __syncthreads();
    }

    // Store results
    int warpBaseM = warpM * 32;
    int warpBaseN = warpN * 32;

    #pragma unroll
    for (int i = 0; i < 2; i++) {
        #pragma unroll
        for (int j = 0; j < 2; j++) {
            int outM = tileM + warpBaseM + i * WMMA_M;
            int outN = tileN + warpBaseN + j * WMMA_N;
            if (outM < M && outN < N) {
                wmma::store_matrix_sync(&C[outM * N + outN], c_frag[i][j], N, wmma::mem_row_major);
            }
        }
    }
}

int main(int argc, char** argv) {
    const int M = 512;
    const int N = 16384;
    const int K = 16384;

    int warmup = 5;
    int iters = 10;
    if (argc >= 2) warmup = atoi(argv[1]);
    if (argc >= 3) iters = atoi(argv[2]);

    __nv_bfloat16 *d_A, *d_B;
    float *d_C;

    cudaMalloc(&d_A, M * K * sizeof(__nv_bfloat16));
    cudaMalloc(&d_B, K * N * sizeof(__nv_bfloat16));
    cudaMalloc(&d_C, M * N * sizeof(float));

    __nv_bfloat16* h_A = new __nv_bfloat16[M * K];
    __nv_bfloat16* h_B = new __nv_bfloat16[K * N];
    for (int i = 0; i < M * K; i++) h_A[i] = __float2bfloat16((float)(rand() % 100) / 100.0f);
    for (int i = 0; i < K * N; i++) h_B[i] = __float2bfloat16((float)(rand() % 100) / 100.0f);

    cudaMemcpy(d_A, h_A, M * K * sizeof(__nv_bfloat16), cudaMemcpyHostToDevice);
    cudaMemcpy(d_B, h_B, K * N * sizeof(__nv_bfloat16), cudaMemcpyHostToDevice);

    dim3 block(BLOCK_SIZE);
    dim3 grid((N + BLOCK_N - 1) / BLOCK_N, (M + BLOCK_M - 1) / BLOCK_M);

    for (int i = 0; i < warmup; i++) {
        matmul_bf16_fp32_vectorized<<<grid, block>>>(d_A, d_B, d_C, M, N, K);
    }
    cudaDeviceSynchronize();

    cudaEvent_t start, stop;
    cudaEventCreate(&start);
    cudaEventCreate(&stop);

    cudaEventRecord(start);
    for (int i = 0; i < iters; i++) {
        matmul_bf16_fp32_vectorized<<<grid, block>>>(d_A, d_B, d_C, M, N, K);
    }
    cudaEventRecord(stop);
    cudaEventSynchronize(stop);

    float ms = 0;
    cudaEventElapsedTime(&ms, start, stop);
    float avg_ms = ms / iters;

    double flops = 2.0 * M * N * K;
    double tflops = flops / (avg_ms * 1e-3) / 1e12;

    printf("Time: %.3f ms, TFLOPS: %.2f\n", avg_ms, tflops);

    delete[] h_A;
    delete[] h_B;
    cudaFree(d_A);
    cudaFree(d_B);
    cudaFree(d_C);
    cudaEventDestroy(start);
    cudaEventDestroy(stop);

    return 0;
}

// iter005_double_buffer.cu - Double buffering to hide memory latency
// Keep the bank-conflict-free iter002 structure, add double buffering

#include <cuda_bf16.h>
#include <cuda_fp16.h>
#include <mma.h>
#include <stdio.h>

using namespace nvcuda;

constexpr int WMMA_M = 16;
constexpr int WMMA_N = 16;
constexpr int WMMA_K = 16;

constexpr int BLOCK_M = 64;
constexpr int BLOCK_N = 64;
constexpr int BLOCK_K = 16;

constexpr int SMEM_PAD = 8;

constexpr int WARPS_M = 2;
constexpr int WARPS_N = 2;
constexpr int WARP_SIZE = 32;
constexpr int NUM_WARPS = WARPS_M * WARPS_N;

__global__ void matmul_bf16_fp32_double_buffer(
    const __nv_bfloat16* __restrict__ A,
    const __nv_bfloat16* __restrict__ B,
    float* __restrict__ C,
    int M, int N, int K
) {
    const int bx = blockIdx.x;
    const int by = blockIdx.y;

    const int warpId = threadIdx.x / WARP_SIZE;
    const int warpM = warpId / WARPS_N;
    const int warpN = warpId % WARPS_N;

    const int tileM = by * BLOCK_M;
    const int tileN = bx * BLOCK_N;

    // Double buffer: two sets of shared memory
    __shared__ __nv_bfloat16 sA[2][BLOCK_M][BLOCK_K + SMEM_PAD];
    __shared__ __nv_bfloat16 sB[2][BLOCK_K][BLOCK_N + SMEM_PAD];

    wmma::fragment<wmma::matrix_a, WMMA_M, WMMA_N, WMMA_K, __nv_bfloat16, wmma::row_major> a_frag[2];
    wmma::fragment<wmma::matrix_b, WMMA_M, WMMA_N, WMMA_K, __nv_bfloat16, wmma::row_major> b_frag[2];
    wmma::fragment<wmma::accumulator, WMMA_M, WMMA_N, WMMA_K, float> c_frag[2][2];

    #pragma unroll
    for (int i = 0; i < 2; i++) {
        #pragma unroll
        for (int j = 0; j < 2; j++) {
            wmma::fill_fragment(c_frag[i][j], 0.0f);
        }
    }

    const int tid = threadIdx.x;
    int warpBaseM = warpM * 32;
    int warpBaseN = warpN * 32;

    // Prologue: Load first tile
    #pragma unroll
    for (int i = 0; i < (BLOCK_M * BLOCK_K) / (NUM_WARPS * WARP_SIZE); i++) {
        int idx = tid + i * NUM_WARPS * WARP_SIZE;
        int row = idx / BLOCK_K;
        int col = idx % BLOCK_K;
        int globalRow = tileM + row;
        int globalCol = col;
        sA[0][row][col] = (globalRow < M && globalCol < K) ? 
                          A[globalRow * K + globalCol] : __float2bfloat16(0.0f);
    }

    #pragma unroll
    for (int i = 0; i < (BLOCK_K * BLOCK_N) / (NUM_WARPS * WARP_SIZE); i++) {
        int idx = tid + i * NUM_WARPS * WARP_SIZE;
        int row = idx / BLOCK_N;
        int col = idx % BLOCK_N;
        int globalRow = row;
        int globalCol = tileN + col;
        sB[0][row][col] = (globalRow < K && globalCol < N) ? 
                          B[globalRow * N + globalCol] : __float2bfloat16(0.0f);
    }

    __syncthreads();

    int numK = (K + BLOCK_K - 1) / BLOCK_K;
    int buf = 0;

    for (int kk = 0; kk < numK; kk++) {
        int nextK = (kk + 1) * BLOCK_K;
        int nextBuf = 1 - buf;

        // Load next tile while computing current
        if (kk < numK - 1) {
            #pragma unroll
            for (int i = 0; i < (BLOCK_M * BLOCK_K) / (NUM_WARPS * WARP_SIZE); i++) {
                int idx = tid + i * NUM_WARPS * WARP_SIZE;
                int row = idx / BLOCK_K;
                int col = idx % BLOCK_K;
                int globalRow = tileM + row;
                int globalCol = nextK + col;
                sA[nextBuf][row][col] = (globalRow < M && globalCol < K) ? 
                                        A[globalRow * K + globalCol] : __float2bfloat16(0.0f);
            }

            #pragma unroll
            for (int i = 0; i < (BLOCK_K * BLOCK_N) / (NUM_WARPS * WARP_SIZE); i++) {
                int idx = tid + i * NUM_WARPS * WARP_SIZE;
                int row = idx / BLOCK_N;
                int col = idx % BLOCK_N;
                int globalRow = nextK + row;
                int globalCol = tileN + col;
                sB[nextBuf][row][col] = (globalRow < K && globalCol < N) ? 
                                        B[globalRow * N + globalCol] : __float2bfloat16(0.0f);
            }
        }

        // Compute on current buffer
        #pragma unroll
        for (int i = 0; i < 2; i++) {
            wmma::load_matrix_sync(a_frag[i], &sA[buf][warpBaseM + i * WMMA_M][0], BLOCK_K + SMEM_PAD);
        }

        #pragma unroll
        for (int j = 0; j < 2; j++) {
            wmma::load_matrix_sync(b_frag[j], &sB[buf][0][warpBaseN + j * WMMA_N], BLOCK_N + SMEM_PAD);
        }

        #pragma unroll
        for (int i = 0; i < 2; i++) {
            #pragma unroll
            for (int j = 0; j < 2; j++) {
                wmma::mma_sync(c_frag[i][j], a_frag[i], b_frag[j], c_frag[i][j]);
            }
        }

        __syncthreads();
        buf = nextBuf;
    }

    // Store results
    #pragma unroll
    for (int i = 0; i < 2; i++) {
        #pragma unroll
        for (int j = 0; j < 2; j++) {
            int outM = tileM + warpBaseM + i * WMMA_M;
            int outN = tileN + warpBaseN + j * WMMA_N;
            if (outM < M && outN < N) {
                wmma::store_matrix_sync(&C[outM * N + outN], c_frag[i][j], N, wmma::mem_row_major);
            }
        }
    }
}

int main(int argc, char** argv) {
    const int M = 512;
    const int N = 16384;
    const int K = 16384;

    int warmup = 5;
    int iters = 10;
    if (argc >= 2) warmup = atoi(argv[1]);
    if (argc >= 3) iters = atoi(argv[2]);

    __nv_bfloat16 *d_A, *d_B;
    float *d_C;

    cudaMalloc(&d_A, M * K * sizeof(__nv_bfloat16));
    cudaMalloc(&d_B, K * N * sizeof(__nv_bfloat16));
    cudaMalloc(&d_C, M * N * sizeof(float));

    __nv_bfloat16* h_A = new __nv_bfloat16[M * K];
    __nv_bfloat16* h_B = new __nv_bfloat16[K * N];
    for (int i = 0; i < M * K; i++) h_A[i] = __float2bfloat16((float)(rand() % 100) / 100.0f);
    for (int i = 0; i < K * N; i++) h_B[i] = __float2bfloat16((float)(rand() % 100) / 100.0f);

    cudaMemcpy(d_A, h_A, M * K * sizeof(__nv_bfloat16), cudaMemcpyHostToDevice);
    cudaMemcpy(d_B, h_B, K * N * sizeof(__nv_bfloat16), cudaMemcpyHostToDevice);

    dim3 block(NUM_WARPS * WARP_SIZE);
    dim3 grid((N + BLOCK_N - 1) / BLOCK_N, (M + BLOCK_M - 1) / BLOCK_M);

    for (int i = 0; i < warmup; i++) {
        matmul_bf16_fp32_double_buffer<<<grid, block>>>(d_A, d_B, d_C, M, N, K);
    }
    cudaDeviceSynchronize();

    cudaEvent_t start, stop;
    cudaEventCreate(&start);
    cudaEventCreate(&stop);

    cudaEventRecord(start);
    for (int i = 0; i < iters; i++) {
        matmul_bf16_fp32_double_buffer<<<grid, block>>>(d_A, d_B, d_C, M, N, K);
    }
    cudaEventRecord(stop);
    cudaEventSynchronize(stop);

    float ms = 0;
    cudaEventElapsedTime(&ms, start, stop);
    float avg_ms = ms / iters;

    double flops = 2.0 * M * N * K;
    double tflops = flops / (avg_ms * 1e-3) / 1e12;

    printf("Time: %.3f ms, TFLOPS: %.2f\n", avg_ms, tflops);

    delete[] h_A;
    delete[] h_B;
    cudaFree(d_A);
    cudaFree(d_B);
    cudaFree(d_C);
    cudaEventDestroy(start);
    cudaEventDestroy(stop);

    return 0;
}

// iter006_large_tile.cu - Larger tile per warp (64x32 output)
// Each warp handles 4x2 WMMA tiles instead of 2x2
// Reduces thread block count, increases arithmetic intensity per thread

#include <cuda_bf16.h>
#include <cuda_fp16.h>
#include <mma.h>
#include <stdio.h>

using namespace nvcuda;

constexpr int WMMA_M = 16;
constexpr int WMMA_N = 16;
constexpr int WMMA_K = 16;

constexpr int BLOCK_M = 128;  // Larger tile
constexpr int BLOCK_N = 64;
constexpr int BLOCK_K = 16;

constexpr int SMEM_PAD = 8;

// 2 warps: warp0 handles rows 0-63, warp1 handles rows 64-127
// Each warp handles 64x64 output (4x4 WMMA tiles)
constexpr int NUM_WARPS = 2;
constexpr int WARP_SIZE = 32;

__global__ void matmul_bf16_fp32_large_tile(
    const __nv_bfloat16* __restrict__ A,
    const __nv_bfloat16* __restrict__ B,
    float* __restrict__ C,
    int M, int N, int K
) {
    const int bx = blockIdx.x;
    const int by = blockIdx.y;

    const int warpId = threadIdx.x / WARP_SIZE;

    const int tileM = by * BLOCK_M;
    const int tileN = bx * BLOCK_N;

    __shared__ __nv_bfloat16 sA[BLOCK_M][BLOCK_K + SMEM_PAD];
    __shared__ __nv_bfloat16 sB[BLOCK_K][BLOCK_N + SMEM_PAD];

    // Each warp handles 64x64 = 4x4 WMMA tiles
    wmma::fragment<wmma::matrix_a, WMMA_M, WMMA_N, WMMA_K, __nv_bfloat16, wmma::row_major> a_frag[4];
    wmma::fragment<wmma::matrix_b, WMMA_M, WMMA_N, WMMA_K, __nv_bfloat16, wmma::row_major> b_frag[4];
    wmma::fragment<wmma::accumulator, WMMA_M, WMMA_N, WMMA_K, float> c_frag[4][4];

    #pragma unroll
    for (int i = 0; i < 4; i++) {
        #pragma unroll
        for (int j = 0; j < 4; j++) {
            wmma::fill_fragment(c_frag[i][j], 0.0f);
        }
    }

    const int tid = threadIdx.x;
    int warpBaseM = warpId * 64;

    for (int k = 0; k < K; k += BLOCK_K) {
        // Load A: 128x16 = 2048 elements, 64 threads = 32 per thread
        #pragma unroll 
        for (int i = 0; i < 32; i++) {
            int idx = tid + i * NUM_WARPS * WARP_SIZE;
            if (idx < BLOCK_M * BLOCK_K) {
                int row = idx / BLOCK_K;
                int col = idx % BLOCK_K;
                int globalRow = tileM + row;
                int globalCol = k + col;
                sA[row][col] = (globalRow < M && globalCol < K) ? 
                               A[globalRow * K + globalCol] : __float2bfloat16(0.0f);
            }
        }

        // Load B: 16x64 = 1024 elements, 64 threads = 16 per thread
        #pragma unroll
        for (int i = 0; i < 16; i++) {
            int idx = tid + i * NUM_WARPS * WARP_SIZE;
            if (idx < BLOCK_K * BLOCK_N) {
                int row = idx / BLOCK_N;
                int col = idx % BLOCK_N;
                int globalRow = k + row;
                int globalCol = tileN + col;
                sB[row][col] = (globalRow < K && globalCol < N) ? 
                               B[globalRow * N + globalCol] : __float2bfloat16(0.0f);
            }
        }

        __syncthreads();

        // Load A fragments (4 rows of 16x16)
        #pragma unroll
        for (int i = 0; i < 4; i++) {
            wmma::load_matrix_sync(a_frag[i], &sA[warpBaseM + i * WMMA_M][0], BLOCK_K + SMEM_PAD);
        }

        // Load B fragments (4 cols of 16x16)
        #pragma unroll
        for (int j = 0; j < 4; j++) {
            wmma::load_matrix_sync(b_frag[j], &sB[0][j * WMMA_N], BLOCK_N + SMEM_PAD);
        }

        // Compute 4x4 WMMA tiles
        #pragma unroll
        for (int i = 0; i < 4; i++) {
            #pragma unroll
            for (int j = 0; j < 4; j++) {
                wmma::mma_sync(c_frag[i][j], a_frag[i], b_frag[j], c_frag[i][j]);
            }
        }

        __syncthreads();
    }

    // Store 4x4 WMMA tiles
    #pragma unroll
    for (int i = 0; i < 4; i++) {
        #pragma unroll
        for (int j = 0; j < 4; j++) {
            int outM = tileM + warpBaseM + i * WMMA_M;
            int outN = tileN + j * WMMA_N;
            if (outM < M && outN < N) {
                wmma::store_matrix_sync(&C[outM * N + outN], c_frag[i][j], N, wmma::mem_row_major);
            }
        }
    }
}

int main(int argc, char** argv) {
    const int M = 512;
    const int N = 16384;
    const int K = 16384;

    int warmup = 5;
    int iters = 10;
    if (argc >= 2) warmup = atoi(argv[1]);
    if (argc >= 3) iters = atoi(argv[2]);

    __nv_bfloat16 *d_A, *d_B;
    float *d_C;

    cudaMalloc(&d_A, M * K * sizeof(__nv_bfloat16));
    cudaMalloc(&d_B, K * N * sizeof(__nv_bfloat16));
    cudaMalloc(&d_C, M * N * sizeof(float));

    __nv_bfloat16* h_A = new __nv_bfloat16[M * K];
    __nv_bfloat16* h_B = new __nv_bfloat16[K * N];
    for (int i = 0; i < M * K; i++) h_A[i] = __float2bfloat16((float)(rand() % 100) / 100.0f);
    for (int i = 0; i < K * N; i++) h_B[i] = __float2bfloat16((float)(rand() % 100) / 100.0f);

    cudaMemcpy(d_A, h_A, M * K * sizeof(__nv_bfloat16), cudaMemcpyHostToDevice);
    cudaMemcpy(d_B, h_B, K * N * sizeof(__nv_bfloat16), cudaMemcpyHostToDevice);

    dim3 block(NUM_WARPS * WARP_SIZE);
    dim3 grid((N + BLOCK_N - 1) / BLOCK_N, (M + BLOCK_M - 1) / BLOCK_M);

    for (int i = 0; i < warmup; i++) {
        matmul_bf16_fp32_large_tile<<<grid, block>>>(d_A, d_B, d_C, M, N, K);
    }
    cudaDeviceSynchronize();

    cudaEvent_t start, stop;
    cudaEventCreate(&start);
    cudaEventCreate(&stop);

    cudaEventRecord(start);
    for (int i = 0; i < iters; i++) {
        matmul_bf16_fp32_large_tile<<<grid, block>>>(d_A, d_B, d_C, M, N, K);
    }
    cudaEventRecord(stop);
    cudaEventSynchronize(stop);

    float ms = 0;
    cudaEventElapsedTime(&ms, start, stop);
    float avg_ms = ms / iters;

    double flops = 2.0 * M * N * K;
    double tflops = flops / (avg_ms * 1e-3) / 1e12;

    printf("Time: %.3f ms, TFLOPS: %.2f\n", avg_ms, tflops);

    delete[] h_A;
    delete[] h_B;
    cudaFree(d_A);
    cudaFree(d_B);
    cudaFree(d_C);
    cudaEventDestroy(start);
    cudaEventDestroy(stop);

    return 0;
}

// iter007_k32.cu - Larger K-tile (32) with iter002's working config
// Keep the same block/warp config as iter002, just increase K-tile

#include <cuda_bf16.h>
#include <cuda_fp16.h>
#include <mma.h>
#include <stdio.h>

using namespace nvcuda;

constexpr int WMMA_M = 16;
constexpr int WMMA_N = 16;
constexpr int WMMA_K = 16;

constexpr int BLOCK_M = 64;
constexpr int BLOCK_N = 64;
constexpr int BLOCK_K = 32;  // Increased from 16 to 32

constexpr int SMEM_PAD = 8;

constexpr int WARPS_M = 2;
constexpr int WARPS_N = 2;
constexpr int WARP_SIZE = 32;
constexpr int NUM_WARPS = WARPS_M * WARPS_N;

__global__ void matmul_bf16_fp32_k32(
    const __nv_bfloat16* __restrict__ A,
    const __nv_bfloat16* __restrict__ B,
    float* __restrict__ C,
    int M, int N, int K
) {
    const int bx = blockIdx.x;
    const int by = blockIdx.y;

    const int warpId = threadIdx.x / WARP_SIZE;
    const int warpM = warpId / WARPS_N;
    const int warpN = warpId % WARPS_N;

    const int tileM = by * BLOCK_M;
    const int tileN = bx * BLOCK_N;

    __shared__ __nv_bfloat16 sA[BLOCK_M][BLOCK_K + SMEM_PAD];
    __shared__ __nv_bfloat16 sB[BLOCK_K][BLOCK_N + SMEM_PAD];

    wmma::fragment<wmma::matrix_a, WMMA_M, WMMA_N, WMMA_K, __nv_bfloat16, wmma::row_major> a_frag[2];
    wmma::fragment<wmma::matrix_b, WMMA_M, WMMA_N, WMMA_K, __nv_bfloat16, wmma::row_major> b_frag[2];
    wmma::fragment<wmma::accumulator, WMMA_M, WMMA_N, WMMA_K, float> c_frag[2][2];

    #pragma unroll
    for (int i = 0; i < 2; i++) {
        #pragma unroll
        for (int j = 0; j < 2; j++) {
            wmma::fill_fragment(c_frag[i][j], 0.0f);
        }
    }

    const int tid = threadIdx.x;
    int warpBaseM = warpM * 32;
    int warpBaseN = warpN * 32;

    // K-loop
    for (int k = 0; k < K; k += BLOCK_K) {
        // Load A: 64x32 = 2048 elements, 128 threads = 16 per thread
        #pragma unroll
        for (int i = 0; i < 16; i++) {
            int idx = tid * 16 + i;
            int row = idx / BLOCK_K;
            int col = idx % BLOCK_K;
            int globalRow = tileM + row;
            int globalCol = k + col;
            sA[row][col] = (globalRow < M && globalCol < K) ? 
                           A[globalRow * K + globalCol] : __float2bfloat16(0.0f);
        }

        // Load B: 32x64 = 2048 elements, 128 threads = 16 per thread
        #pragma unroll
        for (int i = 0; i < 16; i++) {
            int idx = tid * 16 + i;
            int row = idx / BLOCK_N;
            int col = idx % BLOCK_N;
            int globalRow = k + row;
            int globalCol = tileN + col;
            sB[row][col] = (globalRow < K && globalCol < N) ? 
                           B[globalRow * N + globalCol] : __float2bfloat16(0.0f);
        }

        __syncthreads();

        // Compute with 2 K iterations per BLOCK_K
        #pragma unroll 2
        for (int kk = 0; kk < BLOCK_K; kk += WMMA_K) {
            #pragma unroll
            for (int i = 0; i < 2; i++) {
                wmma::load_matrix_sync(a_frag[i], &sA[warpBaseM + i * WMMA_M][kk], BLOCK_K + SMEM_PAD);
            }

            #pragma unroll
            for (int j = 0; j < 2; j++) {
                wmma::load_matrix_sync(b_frag[j], &sB[kk][warpBaseN + j * WMMA_N], BLOCK_N + SMEM_PAD);
            }

            #pragma unroll
            for (int i = 0; i < 2; i++) {
                #pragma unroll
                for (int j = 0; j < 2; j++) {
                    wmma::mma_sync(c_frag[i][j], a_frag[i], b_frag[j], c_frag[i][j]);
                }
            }
        }

        __syncthreads();
    }

    // Store
    #pragma unroll
    for (int i = 0; i < 2; i++) {
        #pragma unroll
        for (int j = 0; j < 2; j++) {
            int outM = tileM + warpBaseM + i * WMMA_M;
            int outN = tileN + warpBaseN + j * WMMA_N;
            if (outM < M && outN < N) {
                wmma::store_matrix_sync(&C[outM * N + outN], c_frag[i][j], N, wmma::mem_row_major);
            }
        }
    }
}

int main(int argc, char** argv) {
    const int M = 512;
    const int N = 16384;
    const int K = 16384;

    int warmup = 5;
    int iters = 10;
    if (argc >= 2) warmup = atoi(argv[1]);
