// iter008_async.cu - Use cp.async for asynchronous global->shared memory loads
// Ampere (sm_80+) supports cp.async for overlapping loads with compute

#include <cuda_bf16.h>
#include <cuda_fp16.h>
#include <mma.h>
#include <cuda_pipeline.h>
#include <stdio.h>

using namespace nvcuda;

constexpr int WMMA_M = 16;
constexpr int WMMA_N = 16;
constexpr int WMMA_K = 16;

constexpr int BLOCK_M = 64;
constexpr int BLOCK_N = 64;
constexpr int BLOCK_K = 16;

constexpr int SMEM_PAD = 8;

constexpr int WARPS_M = 2;
constexpr int WARPS_N = 2;
constexpr int WARP_SIZE = 32;
constexpr int NUM_WARPS = WARPS_M * WARPS_N;

__global__ void matmul_bf16_fp32_async(
    const __nv_bfloat16* __restrict__ A,
    const __nv_bfloat16* __restrict__ B,
    float* __restrict__ C,
    int M, int N, int K
) {
    const int bx = blockIdx.x;
    const int by = blockIdx.y;

    const int warpId = threadIdx.x / WARP_SIZE;
    const int warpM = warpId / WARPS_N;
    const int warpN = warpId % WARPS_N;

    const int tileM = by * BLOCK_M;
    const int tileN = bx * BLOCK_N;

    // Double buffer for async pipeline
    __shared__ __nv_bfloat16 sA[2][BLOCK_M][BLOCK_K + SMEM_PAD];
    __shared__ __nv_bfloat16 sB[2][BLOCK_K][BLOCK_N + SMEM_PAD];

    wmma::fragment<wmma::matrix_a, WMMA_M, WMMA_N, WMMA_K, __nv_bfloat16, wmma::row_major> a_frag[2];
    wmma::fragment<wmma::matrix_b, WMMA_M, WMMA_N, WMMA_K, __nv_bfloat16, wmma::row_major> b_frag[2];
    wmma::fragment<wmma::accumulator, WMMA_M, WMMA_N, WMMA_K, float> c_frag[2][2];

    #pragma unroll
    for (int i = 0; i < 2; i++) {
        #pragma unroll
        for (int j = 0; j < 2; j++) {
            wmma::fill_fragment(c_frag[i][j], 0.0f);
        }
    }

    const int tid = threadIdx.x;
    int warpBaseM = warpM * 32;
    int warpBaseN = warpN * 32;

    const int numK = (K + BLOCK_K - 1) / BLOCK_K;

    // Prologue: async load first tile
    #pragma unroll
    for (int i = 0; i < (BLOCK_M * BLOCK_K) / (NUM_WARPS * WARP_SIZE); i++) {
        int idx = tid + i * NUM_WARPS * WARP_SIZE;
        int row = idx / BLOCK_K;
        int col = idx % BLOCK_K;
        int globalRow = tileM + row;
        int globalCol = col;

        if (globalRow < M && globalCol < K) {
            __pipeline_memcpy_async(&sA[0][row][col], &A[globalRow * K + globalCol], sizeof(__nv_bfloat16));
        } else {
            sA[0][row][col] = __float2bfloat16(0.0f);
        }
    }

    #pragma unroll
    for (int i = 0; i < (BLOCK_K * BLOCK_N) / (NUM_WARPS * WARP_SIZE); i++) {
        int idx = tid + i * NUM_WARPS * WARP_SIZE;
        int row = idx / BLOCK_N;
        int col = idx % BLOCK_N;
        int globalRow = row;
        int globalCol = tileN + col;

        if (globalRow < K && globalCol < N) {
            __pipeline_memcpy_async(&sB[0][row][col], &B[globalRow * N + globalCol], sizeof(__nv_bfloat16));
        } else {
            sB[0][row][col] = __float2bfloat16(0.0f);
        }
    }
    __pipeline_commit();

    int buf = 0;

    for (int kk = 0; kk < numK; kk++) {
        int nextBuf = 1 - buf;
        int nextK = (kk + 1) * BLOCK_K;

        // Start async load for next tile
        if (kk < numK - 1) {
            #pragma unroll
            for (int i = 0; i < (BLOCK_M * BLOCK_K) / (NUM_WARPS * WARP_SIZE); i++) {
                int idx = tid + i * NUM_WARPS * WARP_SIZE;
                int row = idx / BLOCK_K;
                int col = idx % BLOCK_K;
                int globalRow = tileM + row;
                int globalCol = nextK + col;

                if (globalRow < M && globalCol < K) {
                    __pipeline_memcpy_async(&sA[nextBuf][row][col], &A[globalRow * K + globalCol], sizeof(__nv_bfloat16));
                } else {
                    sA[nextBuf][row][col] = __float2bfloat16(0.0f);
                }
            }

            #pragma unroll
            for (int i = 0; i < (BLOCK_K * BLOCK_N) / (NUM_WARPS * WARP_SIZE); i++) {
                int idx = tid + i * NUM_WARPS * WARP_SIZE;
                int row = idx / BLOCK_N;
                int col = idx % BLOCK_N;
                int globalRow = nextK + row;
                int globalCol = tileN + col;

                if (globalRow < K && globalCol < N) {
                    __pipeline_memcpy_async(&sB[nextBuf][row][col], &B[globalRow * N + globalCol], sizeof(__nv_bfloat16));
                } else {
                    sB[nextBuf][row][col] = __float2bfloat16(0.0f);
                }
            }
            __pipeline_commit();
        }

        // Wait for current tile
        __pipeline_wait_prior(1);
        __syncthreads();

        // Compute on current buffer
        #pragma unroll
        for (int i = 0; i < 2; i++) {
            wmma::load_matrix_sync(a_frag[i], &sA[buf][warpBaseM + i * WMMA_M][0], BLOCK_K + SMEM_PAD);
        }

        #pragma unroll
        for (int j = 0; j < 2; j++) {
            wmma::load_matrix_sync(b_frag[j], &sB[buf][0][warpBaseN + j * WMMA_N], BLOCK_N + SMEM_PAD);
        }

        #pragma unroll
        for (int i = 0; i < 2; i++) {
            #pragma unroll
            for (int j = 0; j < 2; j++) {
                wmma::mma_sync(c_frag[i][j], a_frag[i], b_frag[j], c_frag[i][j]);
            }
        }

        buf = nextBuf;
    }

    // Store
    #pragma unroll
    for (int i = 0; i < 2; i++) {
        #pragma unroll
        for (int j = 0; j < 2; j++) {
            int outM = tileM + warpBaseM + i * WMMA_M;
            int outN = tileN + warpBaseN + j * WMMA_N;
            if (outM < M && outN < N) {
                wmma::store_matrix_sync(&C[outM * N + outN], c_frag[i][j], N, wmma::mem_row_major);
            }
        }
    }
}

int main(int argc, char** argv) {
    const int M = 512;
    const int N = 16384;
    const int K = 16384;

    int warmup = 5;
    int iters = 10;
    if (argc >= 2) warmup = atoi(argv[1]);
    if (argc >= 3) iters = atoi(argv[2]);

    __nv_bfloat16 *d_A, *d_B;
    float *d_C;

    cudaMalloc(&d_A, M * K * sizeof(__nv_bfloat16));
    cudaMalloc(&d_B, K * N * sizeof(__nv_bfloat16));
    cudaMalloc(&d_C, M * N * sizeof(float));

    __nv_bfloat16* h_A = new __nv_bfloat16[M * K];
    __nv_bfloat16* h_B = new __nv_bfloat16[K * N];
    for (int i = 0; i < M * K; i++) h_A[i] = __float2bfloat16((float)(rand() % 100) / 100.0f);
    for (int i = 0; i < K * N; i++) h_B[i] = __float2bfloat16((float)(rand() % 100) / 100.0f);

    cudaMemcpy(d_A, h_A, M * K * sizeof(__nv_bfloat16), cudaMemcpyHostToDevice);
    cudaMemcpy(d_B, h_B, K * N * sizeof(__nv_bfloat16), cudaMemcpyHostToDevice);

    dim3 block(NUM_WARPS * WARP_SIZE);
    dim3 grid((N + BLOCK_N - 1) / BLOCK_N, (M + BLOCK_M - 1) / BLOCK_M);

    for (int i = 0; i < warmup; i++) {
        matmul_bf16_fp32_async<<<grid, block>>>(d_A, d_B, d_C, M, N, K);
    }
    cudaDeviceSynchronize();

    cudaEvent_t start, stop;
    cudaEventCreate(&start);
    cudaEventCreate(&stop);

    cudaEventRecord(start);
    for (int i = 0; i < iters; i++) {
        matmul_bf16_fp32_async<<<grid, block>>>(d_A, d_B, d_C, M, N, K);
    }
    cudaEventRecord(stop);
    cudaEventSynchronize(stop);

    float ms = 0;
    cudaEventElapsedTime(&ms, start, stop);
    float avg_ms = ms / iters;

    double flops = 2.0 * M * N * K;
    double tflops = flops / (avg_ms * 1e-3) / 1e12;

    printf("Time: %.3f ms, TFLOPS: %.2f\n", avg_ms, tflops);

    delete[] h_A;
    delete[] h_B;
    cudaFree(d_A);
    cudaFree(d_B);
    cudaFree(d_C);
    cudaEventDestroy(start);
    cudaEventDestroy(stop);

    return 0;
}

// iter009_coalesced_load.cu - Fully coalesced memory loads
// Each warp loads a continuous row of memory for better coalescing
// Based on iter002 with improved load pattern

#include <cuda_bf16.h>
#include <cuda_fp16.h>
#include <mma.h>
#include <stdio.h>

using namespace nvcuda;

constexpr int WMMA_M = 16;
constexpr int WMMA_N = 16;
constexpr int WMMA_K = 16;

constexpr int BLOCK_M = 64;
constexpr int BLOCK_N = 64;
constexpr int BLOCK_K = 16;

constexpr int SMEM_PAD = 8;

constexpr int WARPS_M = 2;
constexpr int WARPS_N = 2;
constexpr int WARP_SIZE = 32;
constexpr int NUM_WARPS = WARPS_M * WARPS_N;
constexpr int BLOCK_SIZE = NUM_WARPS * WARP_SIZE;

__global__ void matmul_bf16_fp32_coalesced(
    const __nv_bfloat16* __restrict__ A,
    const __nv_bfloat16* __restrict__ B,
    float* __restrict__ C,
    int M, int N, int K
) {
    const int bx = blockIdx.x;
    const int by = blockIdx.y;

    const int warpId = threadIdx.x / WARP_SIZE;
    const int warpM = warpId / WARPS_N;
    const int warpN = warpId % WARPS_N;
    const int laneId = threadIdx.x % WARP_SIZE;

    const int tileM = by * BLOCK_M;
    const int tileN = bx * BLOCK_N;

    __shared__ __nv_bfloat16 sA[BLOCK_M][BLOCK_K + SMEM_PAD];
    __shared__ __nv_bfloat16 sB[BLOCK_K][BLOCK_N + SMEM_PAD];

    wmma::fragment<wmma::matrix_a, WMMA_M, WMMA_N, WMMA_K, __nv_bfloat16, wmma::row_major> a_frag[2];
    wmma::fragment<wmma::matrix_b, WMMA_M, WMMA_N, WMMA_K, __nv_bfloat16, wmma::row_major> b_frag[2];
    wmma::fragment<wmma::accumulator, WMMA_M, WMMA_N, WMMA_K, float> c_frag[2][2];

    #pragma unroll
    for (int i = 0; i < 2; i++) {
        #pragma unroll
        for (int j = 0; j < 2; j++) {
            wmma::fill_fragment(c_frag[i][j], 0.0f);
        }
    }

    int warpBaseM = warpM * 32;
    int warpBaseN = warpN * 32;

    // K-loop
    for (int k = 0; k < K; k += BLOCK_K) {
        // Load A: 64x16 = 1024 elements
        // 4 warps, each warp loads 16 rows (256 elements per warp)
        // Each warp loads rows [warpId*16, warpId*16+16)
        // Each thread loads 8 elements (half a row)
        int aWarpRow = warpId * 16;
        #pragma unroll 8
        for (int r = 0; r < 16; r++) {
            int row = aWarpRow + r;
            // First half of threads load first half of row
            // Second half of threads load second half of row
            int col = (laneId < 16) ? laneId : (laneId - 16 + 8);
            int lanePart = (laneId < 16) ? 0 : 1;

            if (lanePart == 0 && col < 8) {
                int globalRow = tileM + row;
                int globalCol = k + col;
                sA[row][col] = (globalRow < M && globalCol < K) ?
                               A[globalRow * K + globalCol] : __float2bfloat16(0.0f);
            } else if (lanePart == 1) {
                int globalRow = tileM + row;
                int globalCol = k + col;
                sA[row][col] = (globalRow < M && globalCol < K) ?
                               A[globalRow * K + globalCol] : __float2bfloat16(0.0f);
            }
        }

        // Load B: 16x64 = 1024 elements
        // 4 warps, each warp loads 4 rows (256 elements per warp)
        // Each thread loads 8 elements
        int bWarpRow = warpId * 4;
        #pragma unroll 4
        for (int r = 0; r < 4; r++) {
            int row = bWarpRow + r;
            // Each thread loads 2 elements
            int col1 = laneId * 2;
            int col2 = laneId * 2 + 1;

            int globalRow = k + row;
            int globalCol1 = tileN + col1;
            int globalCol2 = tileN + col2;

            sB[row][col1] = (globalRow < K && globalCol1 < N) ?
                            B[globalRow * N + globalCol1] : __float2bfloat16(0.0f);
            sB[row][col2] = (globalRow < K && globalCol2 < N) ?
                            B[globalRow * N + globalCol2] : __float2bfloat16(0.0f);
        }

        __syncthreads();

        // Compute WMMA
        #pragma unroll
        for (int i = 0; i < 2; i++) {
            wmma::load_matrix_sync(a_frag[i], &sA[warpBaseM + i * WMMA_M][0], BLOCK_K + SMEM_PAD);
        }

        #pragma unroll
        for (int j = 0; j < 2; j++) {
            wmma::load_matrix_sync(b_frag[j], &sB[0][warpBaseN + j * WMMA_N], BLOCK_N + SMEM_PAD);
        }

        #pragma unroll
        for (int i = 0; i < 2; i++) {
            #pragma unroll
            for (int j = 0; j < 2; j++) {
                wmma::mma_sync(c_frag[i][j], a_frag[i], b_frag[j], c_frag[i][j]);
            }
        }

        __syncthreads();
    }

    // Store
    #pragma unroll
    for (int i = 0; i < 2; i++) {
        #pragma unroll
        for (int j = 0; j < 2; j++) {
            int outM = tileM + warpBaseM + i * WMMA_M;
            int outN = tileN + warpBaseN + j * WMMA_N;
            if (outM < M && outN < N) {
                wmma::store_matrix_sync(&C[outM * N + outN], c_frag[i][j], N, wmma::mem_row_major);
            }
        }
    }
}

int main(int argc, char** argv) {
    const int M = 512;
    const int N = 16384;
    const int K = 16384;

    int warmup = 5;
    int iters = 10;
    if (argc >= 2) warmup = atoi(argv[1]);
    if (argc >= 3) iters = atoi(argv[2]);

    __nv_bfloat16 *d_A, *d_B;
    float *d_C;

    cudaMalloc(&d_A, M * K * sizeof(__nv_bfloat16));
    cudaMalloc(&d_B, K * N * sizeof(__nv_bfloat16));
    cudaMalloc(&d_C, M * N * sizeof(float));

    __nv_bfloat16* h_A = new __nv_bfloat16[M * K];
    __nv_bfloat16* h_B = new __nv_bfloat16[K * N];
    for (int i = 0; i < M * K; i++) h_A[i] = __float2bfloat16((float)(rand() % 100) / 100.0f);
    for (int i = 0; i < K * N; i++) h_B[i] = __float2bfloat16((float)(rand() % 100) / 100.0f);

    cudaMemcpy(d_A, h_A, M * K * sizeof(__nv_bfloat16), cudaMemcpyHostToDevice);
    cudaMemcpy(d_B, h_B, K * N * sizeof(__nv_bfloat16), cudaMemcpyHostToDevice);

    dim3 block(BLOCK_SIZE);
    dim3 grid((N + BLOCK_N - 1) / BLOCK_N, (M + BLOCK_M - 1) / BLOCK_M);

    for (int i = 0; i < warmup; i++) {
        matmul_bf16_fp32_coalesced<<<grid, block>>>(d_A, d_B, d_C, M, N, K);
    }
    cudaDeviceSynchronize();

    cudaEvent_t start, stop;
    cudaEventCreate(&start);
    cudaEventCreate(&stop);

    cudaEventRecord(start);
    for (int i = 0; i < iters; i++) {
        matmul_bf16_fp32_coalesced<<<grid, block>>>(d_A, d_B, d_C, M, N, K);
    }
    cudaEventRecord(stop);
    cudaEventSynchronize(stop);

    float ms = 0;
    cudaEventElapsedTime(&ms, start, stop);
    float avg_ms = ms / iters;

    double flops = 2.0 * M * N * K;
    double tflops = flops / (avg_ms * 1e-3) / 1e12;

    printf("Time: %.3f ms, TFLOPS: %.2f\n", avg_ms, tflops);

    delete[] h_A;
    delete[] h_B;
    cudaFree(d_A);
    cudaFree(d_B);
    cudaFree(d_C);
    cudaEventDestroy(start);
    cudaEventDestroy(stop);

    return 0;
}

// iter010_2warp_3x2.cu - 2 warps, each handles 3x2 WMMA tiles (48x32 output)
// Total output: 96x64 per block
// Try to balance register usage and parallelism

#include <cuda_bf16.h>
#include <cuda_fp16.h>
#include <mma.h>
#include <stdio.h>

using namespace nvcuda;

constexpr int WMMA_M = 16;
constexpr int WMMA_N = 16;
constexpr int WMMA_K = 16;

constexpr int TILES_M = 3;  // 3 WMMA tiles per warp in M
constexpr int TILES_N = 2;  // 2 WMMA tiles per warp in N
constexpr int WARP_M = TILES_M * WMMA_M;  // 48
constexpr int WARP_N = TILES_N * WMMA_N;  // 32

constexpr int NUM_WARPS = 2;  // 2 warps per block
constexpr int BLOCK_M = WARP_M * 2;  // 96
constexpr int BLOCK_N = WARP_N;      // 32

constexpr int BLOCK_K = 16;
constexpr int SMEM_PAD = 8;

constexpr int WARP_SIZE = 32;

__global__ void matmul_bf16_fp32_2warp(
    const __nv_bfloat16* __restrict__ A,
    const __nv_bfloat16* __restrict__ B,
    float* __restrict__ C,
    int M, int N, int K
) {
    const int bx = blockIdx.x;
    const int by = blockIdx.y;

    const int warpId = threadIdx.x / WARP_SIZE;

    const int tileM = by * BLOCK_M;
    const int tileN = bx * BLOCK_N;

    __shared__ __nv_bfloat16 sA[BLOCK_M][BLOCK_K + SMEM_PAD];
    __shared__ __nv_bfloat16 sB[BLOCK_K][BLOCK_N + SMEM_PAD];

    // 3x2 WMMA tiles per warp
    wmma::fragment<wmma::matrix_a, WMMA_M, WMMA_N, WMMA_K, __nv_bfloat16, wmma::row_major> a_frag[TILES_M];
    wmma::fragment<wmma::matrix_b, WMMA_M, WMMA_N, WMMA_K, __nv_bfloat16, wmma::row_major> b_frag[TILES_N];
    wmma::fragment<wmma::accumulator, WMMA_M, WMMA_N, WMMA_K, float> c_frag[TILES_M][TILES_N];

    #pragma unroll
    for (int i = 0; i < TILES_M; i++) {
        #pragma unroll
        for (int j = 0; j < TILES_N; j++) {
            wmma::fill_fragment(c_frag[i][j], 0.0f);
        }
    }

    const int tid = threadIdx.x;
    int warpBaseM = warpId * WARP_M;

    // K-loop
    for (int k = 0; k < K; k += BLOCK_K) {
        // Load A: 96x16 = 1536 elements, 64 threads = 24 per thread
        #pragma unroll
        for (int i = 0; i < 24; i++) {
            int idx = tid * 24 + i;
            if (idx < BLOCK_M * BLOCK_K) {
                int row = idx / BLOCK_K;
                int col = idx % BLOCK_K;
                int globalRow = tileM + row;
                int globalCol = k + col;
                sA[row][col] = (globalRow < M && globalCol < K) ? 
                               A[globalRow * K + globalCol] : __float2bfloat16(0.0f);
            }
        }

        // Load B: 16x32 = 512 elements, 64 threads = 8 per thread
        #pragma unroll
        for (int i = 0; i < 8; i++) {
            int idx = tid * 8 + i;
            int row = idx / BLOCK_N;
            int col = idx % BLOCK_N;
            int globalRow = k + row;
            int globalCol = tileN + col;
            sB[row][col] = (globalRow < K && globalCol < N) ? 
                           B[globalRow * N + globalCol] : __float2bfloat16(0.0f);
        }

        __syncthreads();

        // Load and compute
        #pragma unroll
        for (int i = 0; i < TILES_M; i++) {
            wmma::load_matrix_sync(a_frag[i], &sA[warpBaseM + i * WMMA_M][0], BLOCK_K + SMEM_PAD);
        }

        #pragma unroll
        for (int j = 0; j < TILES_N; j++) {
            wmma::load_matrix_sync(b_frag[j], &sB[0][j * WMMA_N], BLOCK_N + SMEM_PAD);
        }

        #pragma unroll
        for (int i = 0; i < TILES_M; i++) {
            #pragma unroll
            for (int j = 0; j < TILES_N; j++) {
                wmma::mma_sync(c_frag[i][j], a_frag[i], b_frag[j], c_frag[i][j]);
            }
        }

        __syncthreads();
    }

    // Store
    #pragma unroll
    for (int i = 0; i < TILES_M; i++) {
        #pragma unroll
        for (int j = 0; j < TILES_N; j++) {
            int outM = tileM + warpBaseM + i * WMMA_M;
            int outN = tileN + j * WMMA_N;
            if (outM < M && outN < N) {
                wmma::store_matrix_sync(&C[outM * N + outN], c_frag[i][j], N, wmma::mem_row_major);
            }
        }
    }
}

int main(int argc, char** argv) {
    const int M = 512;
    const int N = 16384;
    const int K = 16384;

    int warmup = 5;
    int iters = 10;
    if (argc >= 2) warmup = atoi(argv[1]);
    if (argc >= 3) iters = atoi(argv[2]);

    __nv_bfloat16 *d_A, *d_B;
    float *d_C;

    cudaMalloc(&d_A, M * K * sizeof(__nv_bfloat16));
    cudaMalloc(&d_B, K * N * sizeof(__nv_bfloat16));
    cudaMalloc(&d_C, M * N * sizeof(float));

    __nv_bfloat16* h_A = new __nv_bfloat16[M * K];
    __nv_bfloat16* h_B = new __nv_bfloat16[K * N];
    for (int i = 0; i < M * K; i++) h_A[i] = __float2bfloat16((float)(rand() % 100) / 100.0f);
    for (int i = 0; i < K * N; i++) h_B[i] = __float2bfloat16((float)(rand() % 100) / 100.0f);

    cudaMemcpy(d_A, h_A, M * K * sizeof(__nv_bfloat16), cudaMemcpyHostToDevice);
    cudaMemcpy(d_B, h_B, K * N * sizeof(__nv_bfloat16), cudaMemcpyHostToDevice);

    dim3 block(NUM_WARPS * WARP_SIZE);
    dim3 grid((N + BLOCK_N - 1) / BLOCK_N, (M + BLOCK_M - 1) / BLOCK_M);

    for (int i = 0; i < warmup; i++) {
        matmul_bf16_fp32_2warp<<<grid, block>>>(d_A, d_B, d_C, M, N, K);
    }
    cudaDeviceSynchronize();

    cudaEvent_t start, stop;
    cudaEventCreate(&start);
    cudaEventCreate(&stop);

    cudaEventRecord(start);
    for (int i = 0; i < iters; i++) {
        matmul_bf16_fp32_2warp<<<grid, block>>>(d_A, d_B, d_C, M, N, K);
    }
    cudaEventRecord(stop);
    cudaEventSynchronize(stop);

    float ms = 0;
    cudaEventElapsedTime(&ms, start, stop);
    float avg_ms = ms / iters;

    double flops = 2.0 * M * N * K;
    double tflops = flops / (avg_ms * 1e-3) / 1e12;

    printf("Time: %.3f ms, TFLOPS: %.2f\n", avg_ms, tflops);

    delete[] h_A;
    delete[] h_B;
    cudaFree(d_A);
    cudaFree(d_B);
    cudaFree(d_C);
    cudaEventDestroy(start);
    cudaEventDestroy(stop);

    return 0;
}

// iter011_swizzle.cu - XOR-based swizzle pattern for shared memory
// Use swizzle to further reduce bank conflicts in fragment loads
// Based on iter002 with swizzle addressing

#include <cuda_bf16.h>
#include <cuda_fp16.h>
#include <mma.h>
#include <stdio.h>

using namespace nvcuda;

constexpr int WMMA_M = 16;
constexpr int WMMA_N = 16;
constexpr int WMMA_K = 16;

constexpr int BLOCK_M = 64;
constexpr int BLOCK_N = 64;
constexpr int BLOCK_K = 16;

// Swizzle parameters
// XOR row index with (col / 4) to distribute accesses across banks
constexpr int SWIZZLE_BITS = 2;  // XOR with 2 bits

constexpr int WARPS_M = 2;
constexpr int WARPS_N = 2;
constexpr int WARP_SIZE = 32;
constexpr int NUM_WARPS = WARPS_M * WARPS_N;

// Helper for swizzled index
__device__ __forceinline__ int swizzle_row(int row, int col) {
    return row ^ ((col >> 2) & ((1 << SWIZZLE_BITS) - 1));
}

__global__ void matmul_bf16_fp32_swizzle(
    const __nv_bfloat16* __restrict__ A,
    const __nv_bfloat16* __restrict__ B,
    float* __restrict__ C,
    int M, int N, int K
) {
    const int bx = blockIdx.x;
    const int by = blockIdx.y;

    const int warpId = threadIdx.x / WARP_SIZE;
    const int warpM = warpId / WARPS_N;
    const int warpN = warpId % WARPS_N;

    const int tileM = by * BLOCK_M;
    const int tileN = bx * BLOCK_N;

    // Shared memory without padding (swizzle handles bank conflicts)
    __shared__ __nv_bfloat16 sA[BLOCK_M][BLOCK_K];
    __shared__ __nv_bfloat16 sB[BLOCK_K][BLOCK_N];

    wmma::fragment<wmma::matrix_a, WMMA_M, WMMA_N, WMMA_K, __nv_bfloat16, wmma::row_major> a_frag[2];
    wmma::fragment<wmma::matrix_b, WMMA_M, WMMA_N, WMMA_K, __nv_bfloat16, wmma::row_major> b_frag[2];
    wmma::fragment<wmma::accumulator, WMMA_M, WMMA_N, WMMA_K, float> c_frag[2][2];

    #pragma unroll
    for (int i = 0; i < 2; i++) {
        #pragma unroll
        for (int j = 0; j < 2; j++) {
            wmma::fill_fragment(c_frag[i][j], 0.0f);
        }
    }

    const int tid = threadIdx.x;
    int warpBaseM = warpM * 32;
    int warpBaseN = warpN * 32;

    // K-loop
    for (int k = 0; k < K; k += BLOCK_K) {
        // Load A with swizzle
        #pragma unroll
        for (int i = 0; i < (BLOCK_M * BLOCK_K) / (NUM_WARPS * WARP_SIZE); i++) {
            int idx = tid + i * NUM_WARPS * WARP_SIZE;
            int row = idx / BLOCK_K;
            int col = idx % BLOCK_K;
            int sRow = swizzle_row(row, col);
            int globalRow = tileM + row;
            int globalCol = k + col;
            sA[sRow][col] = (globalRow < M && globalCol < K) ? 
                           A[globalRow * K + globalCol] : __float2bfloat16(0.0f);
        }

        // Load B with swizzle
        #pragma unroll
        for (int i = 0; i < (BLOCK_K * BLOCK_N) / (NUM_WARPS * WARP_SIZE); i++) {
            int idx = tid + i * NUM_WARPS * WARP_SIZE;
            int row = idx / BLOCK_N;
            int col = idx % BLOCK_N;
            int sRow = swizzle_row(row, col);
            int globalRow = k + row;
            int globalCol = tileN + col;
            sB[sRow][col] = (globalRow < K && globalCol < N) ? 
                           B[globalRow * N + globalCol] : __float2bfloat16(0.0f);
        }

        __syncthreads();

        // Load A fragments with de-swizzle
        #pragma unroll
        for (int i = 0; i < 2; i++) {
            int fragBaseM = warpBaseM + i * WMMA_M;
            // WMMA load expects contiguous memory, but we stored with swizzle
            // We need to use a temporary buffer or restructure
            // For simplicity, skip swizzle for WMMA loads (they access contiguous rows)
            wmma::load_matrix_sync(a_frag[i], &sA[fragBaseM][0], BLOCK_K);
        }

        // Load B fragments (swizzle for B affects rows, WMMA loads columns)
        #pragma unroll
        for (int j = 0; j < 2; j++) {
            int fragBaseN = warpBaseN + j * WMMA_N;
            wmma::load_matrix_sync(b_frag[j], &sB[0][fragBaseN], BLOCK_N);
        }

        #pragma unroll
        for (int i = 0; i < 2; i++) {
            #pragma unroll
            for (int j = 0; j < 2; j++) {
                wmma::mma_sync(c_frag[i][j], a_frag[i], b_frag[j], c_frag[i][j]);
            }
        }

        __syncthreads();
    }

    // Store
    #pragma unroll
    for (int i = 0; i < 2; i++) {
        #pragma unroll
        for (int j = 0; j < 2; j++) {
            int outM = tileM + warpBaseM + i * WMMA_M;
            int outN = tileN + warpBaseN + j * WMMA_N;
            if (outM < M && outN < N) {
                wmma::store_matrix_sync(&C[outM * N + outN], c_frag[i][j], N, wmma::mem_row_major);
            }
        }
    }
}

int main(int argc, char** argv) {
    const int M = 512;
    const int N = 16384;
    const int K = 16384;

    int warmup = 5;
    int iters = 10;
    if (argc >= 2) warmup = atoi(argv[1]);
    if (argc >= 3) iters = atoi(argv[2]);

    __nv_bfloat16 *d_A, *d_B;
    float *d_C;

    cudaMalloc(&d_A, M * K * sizeof(__nv_bfloat16));
    cudaMalloc(&d_B, K * N * sizeof(__nv_bfloat16));
    cudaMalloc(&d_C, M * N * sizeof(float));

    __nv_bfloat16* h_A = new __nv_bfloat16[M * K];
    __nv_bfloat16* h_B = new __nv_bfloat16[K * N];
    for (int i = 0; i < M * K; i++) h_A[i] = __float2bfloat16((float)(rand() % 100) / 100.0f);
    for (int i = 0; i < K * N; i++) h_B[i] = __float2bfloat16((float)(rand() % 100) / 100.0f);

    cudaMemcpy(d_A, h_A, M * K * sizeof(__nv_bfloat16), cudaMemcpyHostToDevice);
    cudaMemcpy(d_B, h_B, K * N * sizeof(__nv_bfloat16), cudaMemcpyHostToDevice);

    dim3 block(NUM_WARPS * WARP_SIZE);
    dim3 grid((N + BLOCK_N - 1) / BLOCK_N, (M + BLOCK_M - 1) / BLOCK_M);

    for (int i = 0; i < warmup; i++) {
        matmul_bf16_fp32_swizzle<<<grid, block>>>(d_A, d_B, d_C, M, N, K);
    }
    cudaDeviceSynchronize();

    cudaEvent_t start, stop;
    cudaEventCreate(&start);
    cudaEventCreate(&stop);

    cudaEventRecord(start);
    for (int i = 0; i < iters; i++) {
        matmul_bf16_fp32_swizzle<<<grid, block>>>(d_A, d_B, d_C, M, N, K);
    }
    cudaEventRecord(stop);
    cudaEventSynchronize(stop);

    float ms = 0;
    cudaEventElapsedTime(&ms, start, stop);
    float avg_ms = ms / iters;

    double flops = 2.0 * M * N * K;
    double tflops = flops / (avg_ms * 1e-3) / 1e12;

    printf("Time: %.3f ms, TFLOPS: %.2f\n", avg_ms, tflops);

    delete[] h_A;
    delete[] h_B;
    cudaFree(d_A);
    cudaFree(d_B);
    cudaFree(d_C);
    cudaEventDestroy(start);
    cudaEventDestroy(stop);

    return 0;
}

// iter012_simple_opt.cu - Simplify iter002 with minor optimizations
// Keep iter002's working config, just optimize the loading pattern
// Use __restrict__ more aggressively and simplify indexing

#include <cuda_bf16.h>
#include <cuda_fp16.h>
#include <mma.h>
#include <stdio.h>

using namespace nvcuda;

constexpr int WMMA_M = 16;
constexpr int WMMA_N = 16;
constexpr int WMMA_K = 16;

constexpr int BLOCK_M = 64;
constexpr int BLOCK_N = 64;
constexpr int BLOCK_K = 16;

constexpr int SMEM_PAD = 8;

constexpr int WARPS_M = 2;
constexpr int WARPS_N = 2;
constexpr int WARP_SIZE = 32;
constexpr int NUM_WARPS = WARPS_M * WARPS_N;

// Precompute constants
constexpr int ELEMS_PER_THREAD_A = (BLOCK_M * BLOCK_K) / (NUM_WARPS * WARP_SIZE);  // 8
constexpr int ELEMS_PER_THREAD_B = (BLOCK_K * BLOCK_N) / (NUM_WARPS * WARP_SIZE);  // 8

__global__ __launch_bounds__(128, 4)  // 4 blocks per SM for better occupancy
void matmul_bf16_fp32_simple_opt(
    const __nv_bfloat16* __restrict__ A,
    const __nv_bfloat16* __restrict__ B,
    float* __restrict__ C,
    const int M, const int N, const int K
) {
    const int bx = blockIdx.x;
    const int by = blockIdx.y;

    const int tid = threadIdx.x;
    const int warpId = tid / WARP_SIZE;
    const int warpM = warpId / WARPS_N;
    const int warpN = warpId % WARPS_N;

    const int tileM = by * BLOCK_M;
    const int tileN = bx * BLOCK_N;
    const int warpBaseM = warpM * 32;
    const int warpBaseN = warpN * 32;

    __shared__ __nv_bfloat16 sA[BLOCK_M][BLOCK_K + SMEM_PAD];
    __shared__ __nv_bfloat16 sB[BLOCK_K][BLOCK_N + SMEM_PAD];

    wmma::fragment<wmma::matrix_a, WMMA_M, WMMA_N, WMMA_K, __nv_bfloat16, wmma::row_major> a_frag[2];
    wmma::fragment<wmma::matrix_b, WMMA_M, WMMA_N, WMMA_K, __nv_bfloat16, wmma::row_major> b_frag[2];
    wmma::fragment<wmma::accumulator, WMMA_M, WMMA_N, WMMA_K, float> c_frag[2][2];

    // Initialize accumulators
    wmma::fill_fragment(c_frag[0][0], 0.0f);
    wmma::fill_fragment(c_frag[0][1], 0.0f);
    wmma::fill_fragment(c_frag[1][0], 0.0f);
    wmma::fill_fragment(c_frag[1][1], 0.0f);

    // Precompute thread's load indices
    const int aBaseIdx = tid * ELEMS_PER_THREAD_A;
    const int bBaseIdx = tid * ELEMS_PER_THREAD_B;

    // K-loop
    for (int k = 0; k < K; k += BLOCK_K) {
        // Load A
        #pragma unroll
        for (int i = 0; i < ELEMS_PER_THREAD_A; i++) {
            const int idx = aBaseIdx + i;
            const int row = idx / BLOCK_K;
            const int col = idx % BLOCK_K;
            const int globalRow = tileM + row;
            const int globalCol = k + col;
            sA[row][col] = (globalRow < M && globalCol < K) ? 
                           A[globalRow * K + globalCol] : __float2bfloat16(0.0f);
        }

        // Load B
        #pragma unroll
        for (int i = 0; i < ELEMS_PER_THREAD_B; i++) {
            const int idx = bBaseIdx + i;
            const int row = idx / BLOCK_N;
            const int col = idx % BLOCK_N;
            const int globalRow = k + row;
            const int globalCol = tileN + col;
            sB[row][col] = (globalRow < K && globalCol < N) ? 
                           B[globalRow * N + globalCol] : __float2bfloat16(0.0f);
        }

        __syncthreads();

        // Load A fragments
        wmma::load_matrix_sync(a_frag[0], &sA[warpBaseM][0], BLOCK_K + SMEM_PAD);
        wmma::load_matrix_sync(a_frag[1], &sA[warpBaseM + WMMA_M][0], BLOCK_K + SMEM_PAD);

        // Load B fragments
        wmma::load_matrix_sync(b_frag[0], &sB[0][warpBaseN], BLOCK_N + SMEM_PAD);
        wmma::load_matrix_sync(b_frag[1], &sB[0][warpBaseN + WMMA_N], BLOCK_N + SMEM_PAD);

        // Compute
        wmma::mma_sync(c_frag[0][0], a_frag[0], b_frag[0], c_frag[0][0]);
        wmma::mma_sync(c_frag[0][1], a_frag[0], b_frag[1], c_frag[0][1]);
        wmma::mma_sync(c_frag[1][0], a_frag[1], b_frag[0], c_frag[1][0]);
        wmma::mma_sync(c_frag[1][1], a_frag[1], b_frag[1], c_frag[1][1]);

        __syncthreads();
    }

    // Store
    const int outM0 = tileM + warpBaseM;
    const int outM1 = outM0 + WMMA_M;
    const int outN0 = tileN + warpBaseN;
    const int outN1 = outN0 + WMMA_N;

    if (outM0 < M && outN0 < N) wmma::store_matrix_sync(&C[outM0 * N + outN0], c_frag[0][0], N, wmma::mem_row_major);
    if (outM0 < M && outN1 < N) wmma::store_matrix_sync(&C[outM0 * N + outN1], c_frag[0][1], N, wmma::mem_row_major);
    if (outM1 < M && outN0 < N) wmma::store_matrix_sync(&C[outM1 * N + outN0], c_frag[1][0], N, wmma::mem_row_major);
    if (outM1 < M && outN1 < N) wmma::store_matrix_sync(&C[outM1 * N + outN1], c_frag[1][1], N, wmma::mem_row_major);
}

int main(int argc, char** argv) {
    const int M = 512;
    const int N = 16384;
    const int K = 16384;

    int warmup = 5;
    int iters = 10;
    if (argc >= 2) warmup = atoi(argv[1]);
    if (argc >= 3) iters = atoi(argv[2]);

    __nv_bfloat16 *d_A, *d_B;
    float *d_C;

    cudaMalloc(&d_A, M * K * sizeof(__nv_bfloat16));
    cudaMalloc(&d_B, K * N * sizeof(__nv_bfloat16));
    cudaMalloc(&d_C, M * N * sizeof(float));

    __nv_bfloat16* h_A = new __nv_bfloat16[M * K];
    __nv_bfloat16* h_B = new __nv_bfloat16[K * N];
    for (int i = 0; i < M * K; i++) h_A[i] = __float2bfloat16((float)(rand() % 100) / 100.0f);
    for (int i = 0; i < K * N; i++) h_B[i] = __float2bfloat16((float)(rand() % 100) / 100.0f);

    cudaMemcpy(d_A, h_A, M * K * sizeof(__nv_bfloat16), cudaMemcpyHostToDevice);
    cudaMemcpy(d_B, h_B, K * N * sizeof(__nv_bfloat16), cudaMemcpyHostToDevice);

    dim3 block(NUM_WARPS * WARP_SIZE);
    dim3 grid((N + BLOCK_N - 1) / BLOCK_N, (M + BLOCK_M - 1) / BLOCK_M);

    for (int i = 0; i < warmup; i++) {
        matmul_bf16_fp32_simple_opt<<<grid, block>>>(d_A, d_B, d_C, M, N, K);
    }
    cudaDeviceSynchronize();

    cudaEvent_t start, stop;
    cudaEventCreate(&start);
    cudaEventCreate(&stop);

    cudaEventRecord(start);
    for (int i = 0; i < iters; i++) {
        matmul_bf16_fp32_simple_opt<<<grid, block>>>(d_A, d_B, d_C, M, N, K);
    }
    cudaEventRecord(stop);
    cudaEventSynchronize(stop);

    float ms = 0;
    cudaEventElapsedTime(&ms, start, stop);
    float avg_ms = ms / iters;

    double flops = 2.0 * M * N * K;
    double tflops = flops / (avg_ms * 1e-3) / 1e12;

    printf("Time: %.3f ms, TFLOPS: %.2f\n", avg_ms, tflops);

    delete[] h_A;
    delete[] h_B;
    cudaFree(d_A);
    cudaFree(d_B);
    cudaFree(d_C);
    cudaEventDestroy(start);
    cudaEventDestroy(stop);

    return 0;
}

// iter013_warp_spec.cu - Warp specialization with producer-consumer pattern
// Warp 0-1: compute warps (WMMA)
// Warp 2-3: load warps (global -> shared)
// Use cp.async.wait_group for synchronization

#include <cuda_bf16.h>
#include <cuda_fp16.h>
#include <mma.h>
#include <stdio.h>

using namespace nvcuda;

constexpr int WMMA_M = 16;
constexpr int WMMA_N = 16;
constexpr int WMMA_K = 16;

constexpr int BLOCK_M = 64;
constexpr int BLOCK_N = 64;
constexpr int BLOCK_K = 16;

constexpr int SMEM_PAD = 8;

constexpr int COMPUTE_WARPS = 2;
constexpr int LOAD_WARPS = 2;
constexpr int NUM_WARPS = COMPUTE_WARPS + LOAD_WARPS;
constexpr int WARP_SIZE = 32;

__global__ void matmul_bf16_fp32_warp_spec(
    const __nv_bfloat16* __restrict__ A,
    const __nv_bfloat16* __restrict__ B,
    float* __restrict__ C,
    int M, int N, int K
) {
    const int bx = blockIdx.x;
    const int by = blockIdx.y;

    const int tid = threadIdx.x;
    const int warpId = tid / WARP_SIZE;
    const int laneId = tid % WARP_SIZE;

    const int tileM = by * BLOCK_M;
    const int tileN = bx * BLOCK_N;

    // Double buffer
    __shared__ __nv_bfloat16 sA[2][BLOCK_M][BLOCK_K + SMEM_PAD];
    __shared__ __nv_bfloat16 sB[2][BLOCK_K][BLOCK_N + SMEM_PAD];
    __shared__ int ready[2];  // Simple flag for synchronization

    // Initialize ready flags
    if (tid < 2) ready[tid] = 0;
    __syncthreads();

    const bool isComputeWarp = (warpId < COMPUTE_WARPS);

    if (isComputeWarp) {
        // Compute warp logic
        const int compWarpId = warpId;
        const int warpM = compWarpId;
        const int warpBaseM = warpM * 32;

        wmma::fragment<wmma::matrix_a, WMMA_M, WMMA_N, WMMA_K, __nv_bfloat16, wmma::row_major> a_frag[2];
        wmma::fragment<wmma::matrix_b, WMMA_M, WMMA_N, WMMA_K, __nv_bfloat16, wmma::row_major> b_frag[2];
        wmma::fragment<wmma::accumulator, WMMA_M, WMMA_N, WMMA_K, float> c_frag[2][2];

        #pragma unroll
        for (int i = 0; i < 2; i++) {
            #pragma unroll
            for (int j = 0; j < 2; j++) {
                wmma::fill_fragment(c_frag[i][j], 0.0f);
            }
        }

        int buf = 0;
        const int numK = (K + BLOCK_K - 1) / BLOCK_K;

        for (int kk = 0; kk < numK; kk++) {
            // Wait for data to be ready
            while (atomicAdd(&ready[buf], 0) == 0) {}

            // Load fragments and compute
            #pragma unroll
            for (int i = 0; i < 2; i++) {
                wmma::load_matrix_sync(a_frag[i], &sA[buf][warpBaseM + i * WMMA_M][0], BLOCK_K + SMEM_PAD);
            }

            #pragma unroll
            for (int j = 0; j < 2; j++) {
                wmma::load_matrix_sync(b_frag[j], &sB[buf][0][j * WMMA_N], BLOCK_N + SMEM_PAD);
            }

            #pragma unroll
            for (int i = 0; i < 2; i++) {
                #pragma unroll
                for (int j = 0; j < 2; j++) {
                    wmma::mma_sync(c_frag[i][j], a_frag[i], b_frag[j], c_frag[i][j]);
                }
            }

            // Signal that we're done with this buffer
            __syncwarp();
            if (laneId == 0) atomicExch(&ready[buf], 0);

            buf = 1 - buf;
        }

        // Store results
        #pragma unroll
        for (int i = 0; i < 2; i++) {
            #pragma unroll
            for (int j = 0; j < 2; j++) {
                int outM = tileM + warpBaseM + i * WMMA_M;
                int outN = tileN + j * WMMA_N;
                if (outM < M && outN < N) {
                    wmma::store_matrix_sync(&C[outM * N + outN], c_frag[i][j], N, wmma::mem_row_major);
                }
            }
        }
    } else {
        // Load warp logic
        const int loadWarpId = warpId - COMPUTE_WARPS;

        int buf = 0;
        const int numK = (K + BLOCK_K - 1) / BLOCK_K;

        for (int kk = 0; kk < numK; kk++) {
            const int k = kk * BLOCK_K;

            // Load A (warp 2 loads first half, warp 3 loads second half)
            const int aRowStart = loadWarpId * 32;
            const int aRowEnd = aRowStart + 32;

            for (int row = aRowStart; row < aRowEnd; row++) {
                int col = laneId % BLOCK_K;
                int globalRow = tileM + row;
                int globalCol = k + col;
                if (laneId < BLOCK_K) {
                    sA[buf][row][col] = (globalRow < M && globalCol < K) ?
                                        A[globalRow * K + globalCol] : __float2bfloat16(0.0f);
                }
            }

            // Load B (each load warp loads 8 rows)
            const int bRowStart = loadWarpId * 8;
            const int bRowEnd = bRowStart + 8;

            for (int row = bRowStart; row < bRowEnd && row < BLOCK_K; row++) {
                // Each thread loads 2 columns
                int col1 = laneId * 2;
                int col2 = col1 + 1;
                int globalRow = k + row;

                if (col1 < BLOCK_N) {
                    int globalCol1 = tileN + col1;
                    sB[buf][row][col1] = (globalRow < K && globalCol1 < N) ?
                                         B[globalRow * N + globalCol1] : __float2bfloat16(0.0f);
                }
                if (col2 < BLOCK_N) {
                    int globalCol2 = tileN + col2;
                    sB[buf][row][col2] = (globalRow < K && globalCol2 < N) ?
                                         B[globalRow * N + globalCol2] : __float2bfloat16(0.0f);
                }
            }

            // Signal that data is ready
            __syncwarp();
            if (laneId == 0) atomicExch(&ready[buf], 1);

            // Wait for compute to finish before overwriting
            while (atomicAdd(&ready[1 - buf], 0) != 0) {}

            buf = 1 - buf;
        }
    }
}

int main(int argc, char** argv) {
    const int M = 512;
    const int N = 16384;
    const int K = 16384;

    int warmup = 5;
    int iters = 10;
    if (argc >= 2) warmup = atoi(argv[1]);
    if (argc >= 3) iters = atoi(argv[2]);

    __nv_bfloat16 *d_A, *d_B;
    float *d_C;

    cudaMalloc(&d_A, M * K * sizeof(__nv_bfloat16));
    cudaMalloc(&d_B, K * N * sizeof(__nv_bfloat16));
    cudaMalloc(&d_C, M * N * sizeof(float));

    __nv_bfloat16* h_A = new __nv_bfloat16[M * K];
    __nv_bfloat16* h_B = new __nv_bfloat16[K * N];
    for (int i = 0; i < M * K; i++) h_A[i] = __float2bfloat16((float)(rand() % 100) / 100.0f);
    for (int i = 0; i < K * N; i++) h_B[i] = __float2bfloat16((float)(rand() % 100) / 100.0f);

    cudaMemcpy(d_A, h_A, M * K * sizeof(__nv_bfloat16), cudaMemcpyHostToDevice);
    cudaMemcpy(d_B, h_B, K * N * sizeof(__nv_bfloat16), cudaMemcpyHostToDevice);

    dim3 block(NUM_WARPS * WARP_SIZE);
    dim3 grid((N + BLOCK_N - 1) / BLOCK_N, (M + BLOCK_M - 1) / BLOCK_M);

    for (int i = 0; i < warmup; i++) {
        matmul_bf16_fp32_warp_spec<<<grid, block>>>(d_A, d_B, d_C, M, N, K);
    }
    cudaDeviceSynchronize();

    cudaEvent_t start, stop;
    cudaEventCreate(&start);
    cudaEventCreate(&stop);

    cudaEventRecord(start);
    for (int i = 0; i < iters; i++) {
        matmul_bf16_fp32_warp_spec<<<grid, block>>>(d_A, d_B, d_C, M, N, K);
    }
    cudaEventRecord(stop);
    cudaEventSynchronize(stop);

    float ms = 0;
    cudaEventElapsedTime(&ms, start, stop);
    float avg_ms = ms / iters;

    double flops = 2.0 * M * N * K;
    double tflops = flops / (avg_ms * 1e-3) / 1e12;

    printf("Time: %.3f ms, TFLOPS: %.2f\n", avg_ms, tflops);

    delete[] h_A;
    delete[] h_B;
    cudaFree(d_A);
    cudaFree(d_B);
    cudaFree(d_C);
    cudaEventDestroy(start);
    cudaEventDestroy(stop);

    return 0;
}

// iter014_larger_output.cu - 128x64 output tile, 8 warps
// More parallelism by using more warps with smaller tiles per warp

#include <cuda_bf16.h>
#include <cuda_fp16.h>
#include <mma.h>
#include <stdio.h>

using namespace nvcuda;

constexpr int WMMA_M = 16;
constexpr int WMMA_N = 16;
constexpr int WMMA_K = 16;

constexpr int BLOCK_M = 128;
constexpr int BLOCK_N = 64;
constexpr int BLOCK_K = 16;

constexpr int SMEM_PAD = 8;

// 8 warps: 4 in M, 2 in N
// Each warp handles 32x32 output (2x2 WMMA tiles)
constexpr int WARPS_M = 4;
constexpr int WARPS_N = 2;
constexpr int WARP_SIZE = 32;
constexpr int NUM_WARPS = WARPS_M * WARPS_N;

__global__ void matmul_bf16_fp32_larger_output(
    const __nv_bfloat16* __restrict__ A,
    const __nv_bfloat16* __restrict__ B,
    float* __restrict__ C,
    int M, int N, int K
) {
    const int bx = blockIdx.x;
    const int by = blockIdx.y;

    const int tid = threadIdx.x;
    const int warpId = tid / WARP_SIZE;
    const int warpM = warpId / WARPS_N;
    const int warpN = warpId % WARPS_N;

    const int tileM = by * BLOCK_M;
    const int tileN = bx * BLOCK_N;
    const int warpBaseM = warpM * 32;
    const int warpBaseN = warpN * 32;

    __shared__ __nv_bfloat16 sA[BLOCK_M][BLOCK_K + SMEM_PAD];
    __shared__ __nv_bfloat16 sB[BLOCK_K][BLOCK_N + SMEM_PAD];

    wmma::fragment<wmma::matrix_a, WMMA_M, WMMA_N, WMMA_K, __nv_bfloat16, wmma::row_major> a_frag[2];
    wmma::fragment<wmma::matrix_b, WMMA_M, WMMA_N, WMMA_K, __nv_bfloat16, wmma::row_major> b_frag[2];
    wmma::fragment<wmma::accumulator, WMMA_M, WMMA_N, WMMA_K, float> c_frag[2][2];

    wmma::fill_fragment(c_frag[0][0], 0.0f);
    wmma::fill_fragment(c_frag[0][1], 0.0f);
    wmma::fill_fragment(c_frag[1][0], 0.0f);
    wmma::fill_fragment(c_frag[1][1], 0.0f);

    // K-loop
    for (int k = 0; k < K; k += BLOCK_K) {
        // Load A: 128x16 = 2048 elements, 256 threads = 8 per thread
        #pragma unroll 8
        for (int i = 0; i < 8; i++) {
            int idx = tid * 8 + i;
            int row = idx / BLOCK_K;
            int col = idx % BLOCK_K;
            int globalRow = tileM + row;
            int globalCol = k + col;
            sA[row][col] = (globalRow < M && globalCol < K) ? 
                           A[globalRow * K + globalCol] : __float2bfloat16(0.0f);
        }

        // Load B: 16x64 = 1024 elements, 256 threads = 4 per thread
        #pragma unroll 4
        for (int i = 0; i < 4; i++) {
            int idx = tid * 4 + i;
            int row = idx / BLOCK_N;
            int col = idx % BLOCK_N;
            int globalRow = k + row;
            int globalCol = tileN + col;
            sB[row][col] = (globalRow < K && globalCol < N) ? 
                           B[globalRow * N + globalCol] : __float2bfloat16(0.0f);
        }

        __syncthreads();

        // Load and compute
        wmma::load_matrix_sync(a_frag[0], &sA[warpBaseM][0], BLOCK_K + SMEM_PAD);
        wmma::load_matrix_sync(a_frag[1], &sA[warpBaseM + WMMA_M][0], BLOCK_K + SMEM_PAD);
        wmma::load_matrix_sync(b_frag[0], &sB[0][warpBaseN], BLOCK_N + SMEM_PAD);
        wmma::load_matrix_sync(b_frag[1], &sB[0][warpBaseN + WMMA_N], BLOCK_N + SMEM_PAD);

        wmma::mma_sync(c_frag[0][0], a_frag[0], b_frag[0], c_frag[0][0]);
        wmma::mma_sync(c_frag[0][1], a_frag[0], b_frag[1], c_frag[0][1]);
        wmma::mma_sync(c_frag[1][0], a_frag[1], b_frag[0], c_frag[1][0]);
        wmma::mma_sync(c_frag[1][1], a_frag[1], b_frag[1], c_frag[1][1]);

        __syncthreads();
    }

    // Store
    int outM0 = tileM + warpBaseM;
    int outM1 = outM0 + WMMA_M;
    int outN0 = tileN + warpBaseN;
    int outN1 = outN0 + WMMA_N;

    if (outM0 < M && outN0 < N) wmma::store_matrix_sync(&C[outM0 * N + outN0], c_frag[0][0], N, wmma::mem_row_major);
    if (outM0 < M && outN1 < N) wmma::store_matrix_sync(&C[outM0 * N + outN1], c_frag[0][1], N, wmma::mem_row_major);
    if (outM1 < M && outN0 < N) wmma::store_matrix_sync(&C[outM1 * N + outN0], c_frag[1][0], N, wmma::mem_row_major);
    if (outM1 < M && outN1 < N) wmma::store_matrix_sync(&C[outM1 * N + outN1], c_frag[1][1], N, wmma::mem_row_major);
}

int main(int argc, char** argv) {
    const int M = 512;
    const int N = 16384;
    const int K = 16384;

    int warmup = 5;
    int iters = 10;
    if (argc >= 2) warmup = atoi(argv[1]);
    if (argc >= 3) iters = atoi(argv[2]);

    __nv_bfloat16 *d_A, *d_B;
    float *d_C;

    cudaMalloc(&d_A, M * K * sizeof(__nv_bfloat16));
    cudaMalloc(&d_B, K * N * sizeof(__nv_bfloat16));
    cudaMalloc(&d_C, M * N * sizeof(float));

    __nv_bfloat16* h_A = new __nv_bfloat16[M * K];
    __nv_bfloat16* h_B = new __nv_bfloat16[K * N];
    for (int i = 0; i < M * K; i++) h_A[i] = __float2bfloat16((float)(rand() % 100) / 100.0f);
    for (int i = 0; i < K * N; i++) h_B[i] = __float2bfloat16((float)(rand() % 100) / 100.0f);

    cudaMemcpy(d_A, h_A, M * K * sizeof(__nv_bfloat16), cudaMemcpyHostToDevice);
    cudaMemcpy(d_B, h_B, K * N * sizeof(__nv_bfloat16), cudaMemcpyHostToDevice);

    dim3 block(NUM_WARPS * WARP_SIZE);
    dim3 grid((N + BLOCK_N - 1) / BLOCK_N, (M + BLOCK_M - 1) / BLOCK_M);

    for (int i = 0; i < warmup; i++) {
        matmul_bf16_fp32_larger_output<<<grid, block>>>(d_A, d_B, d_C, M, N, K);
    }
    cudaDeviceSynchronize();

    cudaEvent_t start, stop;
    cudaEventCreate(&start);
    cudaEventCreate(&stop);

    cudaEventRecord(start);
    for (int i = 0; i < iters; i++) {
        matmul_bf16_fp32_larger_output<<<grid, block>>>(d_A, d_B, d_C, M, N, K);
    }
    cudaEventRecord(stop);
    cudaEventSynchronize(stop);

    float ms = 0;
    cudaEventElapsedTime(&ms, start, stop);
    float avg_ms = ms / iters;

    double flops = 2.0 * M * N * K;
    double tflops = flops / (avg_ms * 1e-3) / 1e12;

    printf("Time: %.3f ms, TFLOPS: %.2f\n", avg_ms, tflops);

    delete[] h_A;
    delete[] h_B;
    cudaFree(d_A);
    cudaFree(d_B);
    cudaFree(d_C);
    cudaEventDestroy(start);
    cudaEventDestroy(stop);

    return 0;
}

// iter015_tall_shape.cu - Optimized for tall shape (M=512 << N=K=16384)
// Use narrow M tile (32) and wide N tile (128) to maximize N-parallelism
// More blocks in N dimension where we have more work

#include <cuda_bf16.h>
#include <cuda_fp16.h>
#include <mma.h>
#include <stdio.h>

using namespace nvcuda;

constexpr int WMMA_M = 16;
constexpr int WMMA_N = 16;
constexpr int WMMA_K = 16;

// Optimized for M=512: small M tile, large N tile
constexpr int BLOCK_M = 32;    // Small M tile (2 WMMA tiles)
constexpr int BLOCK_N = 128;   // Large N tile (8 WMMA tiles)
constexpr int BLOCK_K = 16;

constexpr int SMEM_PAD = 8;

// 4 warps: 1 in M, 4 in N
// Each warp handles 32x32 output
constexpr int WARPS_M = 1;
constexpr int WARPS_N = 4;
constexpr int WARP_SIZE = 32;
constexpr int NUM_WARPS = WARPS_M * WARPS_N;

__global__ void matmul_bf16_fp32_tall_shape(
    const __nv_bfloat16* __restrict__ A,
    const __nv_bfloat16* __restrict__ B,
    float* __restrict__ C,
    int M, int N, int K
) {
    const int bx = blockIdx.x;
    const int by = blockIdx.y;

    const int tid = threadIdx.x;
    const int warpId = tid / WARP_SIZE;
    const int warpN = warpId;  // All warps share M, spread across N

    const int tileM = by * BLOCK_M;
    const int tileN = bx * BLOCK_N;
    const int warpBaseN = warpN * 32;

    __shared__ __nv_bfloat16 sA[BLOCK_M][BLOCK_K + SMEM_PAD];
    __shared__ __nv_bfloat16 sB[BLOCK_K][BLOCK_N + SMEM_PAD];

    wmma::fragment<wmma::matrix_a, WMMA_M, WMMA_N, WMMA_K, __nv_bfloat16, wmma::row_major> a_frag[2];
    wmma::fragment<wmma::matrix_b, WMMA_M, WMMA_N, WMMA_K, __nv_bfloat16, wmma::row_major> b_frag[2];
    wmma::fragment<wmma::accumulator, WMMA_M, WMMA_N, WMMA_K, float> c_frag[2][2];

    wmma::fill_fragment(c_frag[0][0], 0.0f);
    wmma::fill_fragment(c_frag[0][1], 0.0f);
    wmma::fill_fragment(c_frag[1][0], 0.0f);
    wmma::fill_fragment(c_frag[1][1], 0.0f);

    // K-loop
    for (int k = 0; k < K; k += BLOCK_K) {
        // Load A: 32x16 = 512 elements, 128 threads = 4 per thread
        #pragma unroll 4
        for (int i = 0; i < 4; i++) {
            int idx = tid * 4 + i;
            int row = idx / BLOCK_K;
            int col = idx % BLOCK_K;
            int globalRow = tileM + row;
            int globalCol = k + col;
            sA[row][col] = (globalRow < M && globalCol < K) ? 
                           A[globalRow * K + globalCol] : __float2bfloat16(0.0f);
        }

        // Load B: 16x128 = 2048 elements, 128 threads = 16 per thread
        #pragma unroll 16
        for (int i = 0; i < 16; i++) {
            int idx = tid * 16 + i;
            int row = idx / BLOCK_N;
            int col = idx % BLOCK_N;
            int globalRow = k + row;
            int globalCol = tileN + col;
            sB[row][col] = (globalRow < K && globalCol < N) ? 
                           B[globalRow * N + globalCol] : __float2bfloat16(0.0f);
        }

        __syncthreads();

        // All warps load same A fragments (broadcast in M)
        wmma::load_matrix_sync(a_frag[0], &sA[0][0], BLOCK_K + SMEM_PAD);
        wmma::load_matrix_sync(a_frag[1], &sA[WMMA_M][0], BLOCK_K + SMEM_PAD);

        // Each warp loads different B fragments
        wmma::load_matrix_sync(b_frag[0], &sB[0][warpBaseN], BLOCK_N + SMEM_PAD);
        wmma::load_matrix_sync(b_frag[1], &sB[0][warpBaseN + WMMA_N], BLOCK_N + SMEM_PAD);

        wmma::mma_sync(c_frag[0][0], a_frag[0], b_frag[0], c_frag[0][0]);
        wmma::mma_sync(c_frag[0][1], a_frag[0], b_frag[1], c_frag[0][1]);
        wmma::mma_sync(c_frag[1][0], a_frag[1], b_frag[0], c_frag[1][0]);
        wmma::mma_sync(c_frag[1][1], a_frag[1], b_frag[1], c_frag[1][1]);

        __syncthreads();
    }

    // Store
    int outM0 = tileM;
    int outM1 = outM0 + WMMA_M;
    int outN0 = tileN + warpBaseN;
    int outN1 = outN0 + WMMA_N;

    if (outM0 < M && outN0 < N) wmma::store_matrix_sync(&C[outM0 * N + outN0], c_frag[0][0], N, wmma::mem_row_major);
    if (outM0 < M && outN1 < N) wmma::store_matrix_sync(&C[outM0 * N + outN1], c_frag[0][1], N, wmma::mem_row_major);
    if (outM1 < M && outN0 < N) wmma::store_matrix_sync(&C[outM1 * N + outN0], c_frag[1][0], N, wmma::mem_row_major);
    if (outM1 < M && outN1 < N) wmma::store_matrix_sync(&C[outM1 * N + outN1], c_frag[1][1], N, wmma::mem_row_major);
}

int main(int argc, char** argv) {
    const int M = 512;
    const int N = 16384;
    const int K = 16384;

    int warmup = 5;
    int iters = 10;
    if (argc >= 2) warmup = atoi(argv[1]);
    if (argc >= 3) iters = atoi(argv[2]);

    __nv_bfloat16 *d_A, *d_B;
    float *d_C;

    cudaMalloc(&d_A, M * K * sizeof(__nv_bfloat16));
    cudaMalloc(&d_B, K * N * sizeof(__nv_bfloat16));
    cudaMalloc(&d_C, M * N * sizeof(float));

    __nv_bfloat16* h_A = new __nv_bfloat16[M * K];
    __nv_bfloat16* h_B = new __nv_bfloat16[K * N];
    for (int i = 0; i < M * K; i++) h_A[i] = __float2bfloat16((float)(rand() % 100) / 100.0f);
    for (int i = 0; i < K * N; i++) h_B[i] = __float2bfloat16((float)(rand() % 100) / 100.0f);

    cudaMemcpy(d_A, h_A, M * K * sizeof(__nv_bfloat16), cudaMemcpyHostToDevice);
    cudaMemcpy(d_B, h_B, K * N * sizeof(__nv_bfloat16), cudaMemcpyHostToDevice);

    dim3 block(NUM_WARPS * WARP_SIZE);
    dim3 grid((N + BLOCK_N - 1) / BLOCK_N, (M + BLOCK_M - 1) / BLOCK_M);

    printf("Grid: %dx%d, Block: %d\n", grid.x, grid.y, block.x);

    for (int i = 0; i < warmup; i++) {
        matmul_bf16_fp32_tall_shape<<<grid, block>>>(d_A, d_B, d_C, M, N, K);
    }
    cudaDeviceSynchronize();

    cudaEvent_t start, stop;
    cudaEventCreate(&start);
    cudaEventCreate(&stop);

    cudaEventRecord(start);
    for (int i = 0; i < iters; i++) {
        matmul_bf16_fp32_tall_shape<<<grid, block>>>(d_A, d_B, d_C, M, N, K);
    }
    cudaEventRecord(stop);
    cudaEventSynchronize(stop);

    float ms = 0;
    cudaEventElapsedTime(&ms, start, stop);
    float avg_ms = ms / iters;

    double flops = 2.0 * M * N * K;
    double tflops = flops / (avg_ms * 1e-3) / 1e12;

    printf("Time: %.3f ms, TFLOPS: %.2f\n", avg_ms, tflops);

    delete[] h_A;
    delete[] h_B;
    cudaFree(d_A);
    cudaFree(d_B);
    cudaFree(d_C);
    cudaEventDestroy(start);
    cudaEventDestroy(stop);

    return 0;
}

// iter016_pad4.cu - Try different padding size (4 instead of 8)
// Based on iter002, just change SMEM_PAD from 8 to 4

#include <cuda_bf16.h>
#include <cuda_fp16.h>
#include <mma.h>
#include <stdio.h>

using namespace nvcuda;

constexpr int WMMA_M = 16;
constexpr int WMMA_N = 16;
constexpr int WMMA_K = 16;

constexpr int BLOCK_M = 64;
constexpr int BLOCK_N = 64;
constexpr int BLOCK_K = 16;

constexpr int SMEM_PAD = 4;  // Changed from 8 to 4

constexpr int WARPS_M = 2;
constexpr int WARPS_N = 2;
constexpr int WARP_SIZE = 32;
constexpr int NUM_WARPS = WARPS_M * WARPS_N;

__global__ void matmul_bf16_fp32_pad4(
    const __nv_bfloat16* __restrict__ A,
    const __nv_bfloat16* __restrict__ B,
    float* __restrict__ C,
    int M, int N, int K
) {
    const int bx = blockIdx.x;
    const int by = blockIdx.y;

    const int warpId = threadIdx.x / WARP_SIZE;
    const int warpM = warpId / WARPS_N;
    const int warpN = warpId % WARPS_N;

    const int tileM = by * BLOCK_M;
    const int tileN = bx * BLOCK_N;

    __shared__ __nv_bfloat16 sA[BLOCK_M][BLOCK_K + SMEM_PAD];
    __shared__ __nv_bfloat16 sB[BLOCK_K][BLOCK_N + SMEM_PAD];

    wmma::fragment<wmma::matrix_a, WMMA_M, WMMA_N, WMMA_K, __nv_bfloat16, wmma::row_major> a_frag[2];
    wmma::fragment<wmma::matrix_b, WMMA_M, WMMA_N, WMMA_K, __nv_bfloat16, wmma::row_major> b_frag[2];
    wmma::fragment<wmma::accumulator, WMMA_M, WMMA_N, WMMA_K, float> c_frag[2][2];

    #pragma unroll
    for (int i = 0; i < 2; i++) {
        #pragma unroll
        for (int j = 0; j < 2; j++) {
            wmma::fill_fragment(c_frag[i][j], 0.0f);
        }
    }

    const int tid = threadIdx.x;
    int warpBaseM = warpM * 32;
    int warpBaseN = warpN * 32;

    for (int k = 0; k < K; k += BLOCK_K) {
        #pragma unroll
        for (int i = 0; i < (BLOCK_M * BLOCK_K) / (NUM_WARPS * WARP_SIZE); i++) {
            int idx = tid + i * NUM_WARPS * WARP_SIZE;
            int row = idx / BLOCK_K;
            int col = idx % BLOCK_K;
            int globalRow = tileM + row;
            int globalCol = k + col;
            sA[row][col] = (globalRow < M && globalCol < K) ? 
                           A[globalRow * K + globalCol] : __float2bfloat16(0.0f);
        }

        #pragma unroll
        for (int i = 0; i < (BLOCK_K * BLOCK_N) / (NUM_WARPS * WARP_SIZE); i++) {
            int idx = tid + i * NUM_WARPS * WARP_SIZE;
            int row = idx / BLOCK_N;
            int col = idx % BLOCK_N;
            int globalRow = k + row;
            int globalCol = tileN + col;
            sB[row][col] = (globalRow < K && globalCol < N) ? 
                           B[globalRow * N + globalCol] : __float2bfloat16(0.0f);
        }

        __syncthreads();

        #pragma unroll
        for (int i = 0; i < 2; i++) {
            wmma::load_matrix_sync(a_frag[i], &sA[warpBaseM + i * WMMA_M][0], BLOCK_K + SMEM_PAD);
        }

        #pragma unroll
        for (int j = 0; j < 2; j++) {
            wmma::load_matrix_sync(b_frag[j], &sB[0][warpBaseN + j * WMMA_N], BLOCK_N + SMEM_PAD);
        }

        #pragma unroll
        for (int i = 0; i < 2; i++) {
            #pragma unroll
            for (int j = 0; j < 2; j++) {
                wmma::mma_sync(c_frag[i][j], a_frag[i], b_frag[j], c_frag[i][j]);
            }
        }

        __syncthreads();
    }

    #pragma unroll
    for (int i = 0; i < 2; i++) {
        #pragma unroll
        for (int j = 0; j < 2; j++) {
            int outM = tileM + warpBaseM + i * WMMA_M;
            int outN = tileN + warpBaseN + j * WMMA_N;
            if (outM < M && outN < N) {
                wmma::store_matrix_sync(&C[outM * N + outN], c_frag[i][j], N, wmma::mem_row_major);
            }
        }
    }
}

int main(int argc, char** argv) {
    const int M = 512;
    const int N = 16384;
    const int K = 16384;

    int warmup = 5;
    int iters = 10;
    if (argc >= 2) warmup = atoi(argv[1]);
    if (argc >= 3) iters = atoi(argv[2]);

    __nv_bfloat16 *d_A, *d_B;
    float *d_C;

    cudaMalloc(&d_A, M * K * sizeof(__nv_bfloat16));
    cudaMalloc(&d_B, K * N * sizeof(__nv_bfloat16));
    cudaMalloc(&d_C, M * N * sizeof(float));

    __nv_bfloat16* h_A = new __nv_bfloat16[M * K];
    __nv_bfloat16* h_B = new __nv_bfloat16[K * N];
    for (int i = 0; i < M * K; i++) h_A[i] = __float2bfloat16((float)(rand() % 100) / 100.0f);
    for (int i = 0; i < K * N; i++) h_B[i] = __float2bfloat16((float)(rand() % 100) / 100.0f);

    cudaMemcpy(d_A, h_A, M * K * sizeof(__nv_bfloat16), cudaMemcpyHostToDevice);
    cudaMemcpy(d_B, h_B, K * N * sizeof(__nv_bfloat16), cudaMemcpyHostToDevice);

    dim3 block(NUM_WARPS * WARP_SIZE);
    dim3 grid((N + BLOCK_N - 1) / BLOCK_N, (M + BLOCK_M - 1) / BLOCK_M);

    for (int i = 0; i < warmup; i++) {
        matmul_bf16_fp32_pad4<<<grid, block>>>(d_A, d_B, d_C, M, N, K);
    }
    cudaDeviceSynchronize();

    cudaEvent_t start, stop;
    cudaEventCreate(&start);
    cudaEventCreate(&stop);

    cudaEventRecord(start);
    for (int i = 0; i < iters; i++) {
        matmul_bf16_fp32_pad4<<<grid, block>>>(d_A, d_B, d_C, M, N, K);
    }
    cudaEventRecord(stop);
    cudaEventSynchronize(stop);

    float ms = 0;
    cudaEventElapsedTime(&ms, start, stop);
    float avg_ms = ms / iters;

    double flops = 2.0 * M * N * K;
    double tflops = flops / (avg_ms * 1e-3) / 1e12;

    printf("Time: %.3f ms, TFLOPS: %.2f\n", avg_ms, tflops);

    delete[] h_A;
    delete[] h_B;
    cudaFree(d_A);
    cudaFree(d_B);
    cudaFree(d_C);
    cudaEventDestroy(start);
    cudaEventDestroy(stop);

    return 0;
}

// iter017_warp_tile_64.cu - CUTLASS-style warp tile: 64x64 per warp
// Each warp handles a larger output tile (64x64 = 4096 elements)
// Uses 4 warps per block, each doing 4x4 WMMA tiles

#include <cuda_bf16.h>
#include <cuda_fp16.h>
#include <mma.h>
#include <stdio.h>

using namespace nvcuda;

constexpr int WMMA_M = 16;
constexpr int WMMA_N = 16;
constexpr int WMMA_K = 16;

// Each warp handles 64x64 output
constexpr int WARP_TILE_M = 64;
constexpr int WARP_TILE_N = 64;
constexpr int WMMA_TILES_M = WARP_TILE_M / WMMA_M;  // 4
constexpr int WMMA_TILES_N = WARP_TILE_N / WMMA_N;  // 4

// Single warp per block
constexpr int NUM_WARPS = 1;
constexpr int WARP_SIZE = 32;

constexpr int BLOCK_M = WARP_TILE_M;
constexpr int BLOCK_N = WARP_TILE_N;
constexpr int BLOCK_K = 16;
constexpr int SMEM_PAD = 8;

__global__ void matmul_bf16_fp32_warp_tile_64(
    const __nv_bfloat16* __restrict__ A,
    const __nv_bfloat16* __restrict__ B,
    float* __restrict__ C,
    int M, int N, int K
) {
    const int bx = blockIdx.x;
    const int by = blockIdx.y;

    const int tid = threadIdx.x;

    const int tileM = by * BLOCK_M;
    const int tileN = bx * BLOCK_N;

    __shared__ __nv_bfloat16 sA[BLOCK_M][BLOCK_K + SMEM_PAD];
    __shared__ __nv_bfloat16 sB[BLOCK_K][BLOCK_N + SMEM_PAD];

    // 4x4 WMMA tiles = 16 accumulators
    // Too many - will cause register spill
    // Let's try 2x2 at a time with loop
    wmma::fragment<wmma::accumulator, WMMA_M, WMMA_N, WMMA_K, float> c_frag[4][4];

    #pragma unroll
    for (int i = 0; i < 4; i++) {
        #pragma unroll
        for (int j = 0; j < 4; j++) {
            wmma::fill_fragment(c_frag[i][j], 0.0f);
        }
    }

    // K-loop
    for (int k = 0; k < K; k += BLOCK_K) {
        // Load A: 64x16 = 1024 elements, 32 threads = 32 per thread
        #pragma unroll 32
        for (int i = 0; i < 32; i++) {
            int idx = tid * 32 + i;
            int row = idx / BLOCK_K;
            int col = idx % BLOCK_K;
            int globalRow = tileM + row;
            int globalCol = k + col;
            sA[row][col] = (globalRow < M && globalCol < K) ? 
                           A[globalRow * K + globalCol] : __float2bfloat16(0.0f);
        }

        // Load B: 16x64 = 1024 elements, 32 threads = 32 per thread
        #pragma unroll 32
        for (int i = 0; i < 32; i++) {
            int idx = tid * 32 + i;
            int row = idx / BLOCK_N;
            int col = idx % BLOCK_N;
            int globalRow = k + row;
            int globalCol = tileN + col;
            sB[row][col] = (globalRow < K && globalCol < N) ? 
                           B[globalRow * N + globalCol] : __float2bfloat16(0.0f);
        }

        __syncthreads();

        // Compute 4x4 WMMA tiles
        wmma::fragment<wmma::matrix_a, WMMA_M, WMMA_N, WMMA_K, __nv_bfloat16, wmma::row_major> a_frag;
        wmma::fragment<wmma::matrix_b, WMMA_M, WMMA_N, WMMA_K, __nv_bfloat16, wmma::row_major> b_frag;

        #pragma unroll 4
        for (int i = 0; i < 4; i++) {
            wmma::load_matrix_sync(a_frag, &sA[i * WMMA_M][0], BLOCK_K + SMEM_PAD);

            #pragma unroll 4
            for (int j = 0; j < 4; j++) {
                wmma::load_matrix_sync(b_frag, &sB[0][j * WMMA_N], BLOCK_N + SMEM_PAD);
                wmma::mma_sync(c_frag[i][j], a_frag, b_frag, c_frag[i][j]);
            }
        }

        __syncthreads();
    }

    // Store 4x4 WMMA tiles
    #pragma unroll 4
    for (int i = 0; i < 4; i++) {
        #pragma unroll 4
        for (int j = 0; j < 4; j++) {
            int outM = tileM + i * WMMA_M;
            int outN = tileN + j * WMMA_N;
            if (outM < M && outN < N) {
                wmma::store_matrix_sync(&C[outM * N + outN], c_frag[i][j], N, wmma::mem_row_major);
            }
        }
    }
}

int main(int argc, char** argv) {
