            int col = idx % BLOCK_K;
            sA[row][col] = A[(tileM + row) * K + k + col];
        }

        #pragma unroll
        for (int i = 0; i < 8; i++) {
            int idx = tid + i * 128;
            int srcRow = idx / BLOCK_N;
            int srcCol = idx % BLOCK_N;
            sB[srcCol][srcRow] = B[(k + srcRow) * N + tileN + srcCol];
